import { test, expect } from '@playwright/test';

test.describe('Search Assist System (HeroSearch)', () => {

  test.beforeEach(async ({ page }) => {
    // Vamos a la home donde está el HeroSearch
    await page.goto('/');
  });

  test('Caso 1: AbortController cancela requests previas al escribir rápido', async ({ page }) => {
    let abortCount = 0;
    
    await page.route('**/api/activities/suggestions?q=*', async (route) => {
      // Simulamos latencia para que las primeras requests se aborten
      await new Promise(r => setTimeout(r, 400));
      try {
        await route.fulfill({
          status: 200,
          contentType: 'application/json',
          body: JSON.stringify([{ type: 'query', id: '1', label: 'arte' }])
        });
      } catch (e) {
        abortCount++;
      }
    });

    const searchInput = page.locator('input[id="hero-search"]');
    await searchInput.fill('');
    
    // Escribimos rápido simulando typing real
    await searchInput.type('arte', { delay: 50 });

    // Esperamos a que termine el debounce y fetch
    await page.waitForTimeout(1000);
    
    await expect(page.getByRole('listbox')).toBeVisible();
    const option = page.getByRole('option').first();
    await expect(option).toBeVisible();
  });

  test('Caso 2: Tracking Integrity', async ({ page }) => {
    const trackingEvents: any[] = [];

    await page.route('**/api/events', async (route) => {
      if (route.request().method() === 'POST') {
        trackingEvents.push(route.request().postDataJSON());
      }
      await route.fulfill({ status: 204 });
    });

    await page.route('**/api/activities/suggestions?q=*', async (route) => {
      await route.fulfill({
        status: 200,
        contentType: 'application/json',
        body: JSON.stringify([
          { type: 'activity', id: '123', label: 'Taller de Arte' }
        ])
      });
    });

    const searchInput = page.locator('input[id="hero-search"]');
    await searchInput.fill('arte');
    
    const option = page.getByRole('option', { name: /Taller de Arte/i });
    await expect(option).toBeVisible();

    await option.click();

    // Verificamos el payload de tracking
    // Necesitamos esperar un momento para que el fetch asíncrono en background se procese
    await page.waitForTimeout(500);

    const suggestionEvent = trackingEvents.find(e => e.type === 'search_suggestion_clicked');
    
    expect(suggestionEvent).toBeDefined();
    expect(suggestionEvent.metadata).toMatchObject({
      query: 'arte',
      suggestion: 'Taller de Arte',
      type: 'activity'
    });
  });

  test('Caso 3: XSS Protection en Input y Highlight', async ({ page }) => {
    const xssString = '<script>alert("XSS")</script>';
    
    await page.route('**/api/activities/suggestions*', async (route) => {
      await route.fulfill({
        status: 200,
        contentType: 'application/json',
        body: JSON.stringify([
          { type: 'query', id: 'xss', label: xssString }
        ])
      });
    });

    let dialogAppeared = false;
    page.on('dialog', async dialog => {
      dialogAppeared = true;
      await dialog.dismiss();
    });

    const searchInput = page.locator('input[id="hero-search"]');
    // Para que dispare la búsqueda, escribimos el XSS
    await searchInput.fill(xssString);
    
    // Provocar el trigger del fetch
    await searchInput.press('Space');
    await searchInput.press('Backspace');

    const option = page.getByRole('option').first();
    await expect(option).toBeVisible();

    // Verificamos que el texto esté visible como string puro y que el script NO se haya ejecutado
    await expect(option).toContainText(xssString);
    expect(dialogAppeared).toBe(false); // No hubo XSS execution
  });

  test('Caso 4: API Failure resiliencia (500 Timeout)', async ({ page }) => {
    await page.route('**/api/activities/suggestions?q=*', async (route) => {
      await route.fulfill({ status: 500, body: 'Internal Server Error' });
    });

    const searchInput = page.locator('input[id="hero-search"]');
    await searchInput.fill('talleres');

    await page.waitForTimeout(1000);

    await expect(page.getByRole('listbox')).toBeHidden();
    await expect(searchInput).toBeEditable();
  });

});

import 'dotenv/config';
import { PrismaPg } from '@prisma/adapter-pg';
import { PrismaClient } from '../src/generated/prisma/client';

const prisma = new PrismaClient({ adapter: new PrismaPg({ connectionString: process.env.DATABASE_URL! }) });

async function main() {
  const verticals = await prisma.vertical.findMany({ select: { id: true, slug: true, name: true } });
  console.log('Verticals:', JSON.stringify(verticals, null, 2));

  const sample = await (prisma as any).scrapingSource.findFirst({ select: { id: true, name: true, verticalId: true, cityId: true } });
  console.log('Sample source:', JSON.stringify(sample, null, 2));

  await prisma.$disconnect();
}

main().catch((e: unknown) => {
  console.error(e instanceof Error ? e.message : String(e));
  process.exit(1);
});

import { getErrorMessage } from '../src/lib/error';
/**
 * audit-coverage.ts
 * ─────────────────────────────────────────────────────────────────────────────
 * Auditoría de cobertura del scraping scheduler.
 *
 * Para cada fuente web: navega al listing URL, extrae links que parezcan
 * actividades/eventos, compara con el caché de BD, y reporta cuántos son
 * nuevos vs ya procesados.
 *
 * Útil para detectar fuentes donde el presupuesto del scheduler (maxUrls)
 * es menor al tamaño real del listing → actividades perdidas.
 *
 * Uso:
 *   npx tsx scripts/audit-coverage.ts
 *   npx tsx scripts/audit-coverage.ts --source=banrep   (solo una fuente)
 *   npx tsx scripts/audit-coverage.ts --fast            (solo Cheerio, sin Playwright)
 *
 * NO usa Gemini, NO guarda en BD, NO modifica nada.
 * ─────────────────────────────────────────────────────────────────────────────
 */
import 'dotenv/config';
import { chromium, Browser } from 'playwright';
import * as cheerio from 'cheerio';
import { ScrapingCache } from '../src/modules/scraping/cache';
import { buildPredictivePlan } from '../src/modules/scraping/scheduler/scheduler.core';
import { type SourceStats } from '../src/modules/scraping/scheduler/scheduler.types';
import { getSourceAggregatedStats, getCTRByDomain } from '../src/modules/analytics/metrics';
import { prisma } from '../src/lib/db';

// ── Tipos ─────────────────────────────────────────────────────────────────────

interface AuditSource {
  name: string;
  url: string;
  cityName?: string;
}

interface AuditResult {
  name: string;
  url: string;
  status: 'ok' | 'error' | 'timeout';
  totalLinks: number;      // Links únicos en el listing (mismo dominio, filtrados)
  cached: number;          // Ya en caché → ya procesados
  newLinks: number;        // No están en caché → potencial nuevo contenido
  newUrls: string[];       // URLs nuevas (max 10 para display)
  schedulerMode?: string;  // Modo que asignaría el scheduler
  schedulerBudget?: number; // maxUrls que daría el scheduler
  error?: string;
  durationMs: number;
}

// ── Fuentes a auditar (solo canal web) ────────────────────────────────────────
// Copiadas y simplificadas de ingest-sources.ts. Solo las que tienen listing navegable.

const SOURCES: AuditSource[] = [
  { name: 'BibloRed',             url: 'https://www.biblored.gov.co/eventos',                               cityName: 'Bogotá' },
  { name: 'Banrep — Bogotá',      url: 'https://www.banrepcultural.org/actividades/bogota',                 cityName: 'Bogotá' },
  { name: 'Idartes',              url: 'https://www.idartes.gov.co/es/agenda',                              cityName: 'Bogotá' },
  { name: 'Planetario de Bogotá', url: 'https://planetariodebogota.gov.co/programate',                      cityName: 'Bogotá' },
  { name: 'Cinemateca de Bogotá', url: 'https://cinematecadebogota.gov.co/cine/11',                         cityName: 'Bogotá' },
  { name: 'FCE — Luis Caballero', url: 'https://fce.gov.co/es/agenda',                                      cityName: 'Bogotá' },
  { name: 'FCE — Reyes Católicos',url: 'https://fce.gov.co/es/agenda',                                      cityName: 'Bogotá' },
  { name: 'FCE — Villa de Leyva', url: 'https://fce.gov.co/es/agenda',                                      cityName: 'Bogotá' },
  { name: 'Sec. Cultura',         url: 'https://www.culturarecreacionydeporte.gov.co/es/agenda',            cityName: 'Bogotá' },
  { name: 'Parque Explora',       url: 'https://www.parqueexplora.org/visita/actividades-y-talleres',       cityName: 'Medellín' },
];

// ── Patrones de exclusión: paths claramente de navegación, no eventos ─────────

const NAV_EXCLUSIONS = [
  '/servicios', '/service', '/noticias', '/noticia/',
  '/biblioteca-virtual', '/coleccion', '/colecciones',
  '/museo-del-oro', '/museo-botero', '/museo-de-arte', '/museo-casa',
  '/museos-', '/red-museos', '/centros-culturales', '/centro-cultural',
  '/accesibilidad', '/about-', '/sobre-', '/quienes-somos',
  '/contacto', '/contact', '/buscar', '/search', '/login', '/registro',
  '/mapa-del-sitio', '/sitemap', '/politica', '/terminos', '/ayuda',
  '/preguntas-frecuentes', '/faq', '/fundaciones',
  '/barranquilla', '/bucaramanga', '/buenaventura', '/san-andres',
  '/santa-marta', '/valledupar', '/villavicencio', '/cartagena',
  '/medellin', '/cali', '/manizales', '/pereira', '/leticia',
  '/armenia/', '/pasto/', '/bogota/museo', '/bogota/casa',
  '/actividad-musical', '/biblioteca-para-sordos', '/imagen-regional',
  '/leer-el-', '/jovenes-interpretes', '/programas/colombia-en-un',
  '/servicios/maletas', '/servicios/internet', '/servicios/listas',
  '/servicios/calendario', '/servicios/desarrollo',
  '/biblioteca-virtual/recursos', '/biblioteca-virtual/colecciones',
  '/exposicion-permanente', '/exposiciones/exposicion-permanente',
  '/multimedia', '/descubridor.banrep', 'colecciones.banrep',
  'publicaciones.banrep',
  '#',
];

// ── Heurística: ¿es este link potencialmente un evento/actividad? ─────────────

function isActivityLike(href: string, listingUrl: string): boolean {
  try {
    const parsed = new URL(href);
    const listing = new URL(listingUrl);

    // Solo mismo dominio (o subdominio del mismo dominio base)
    const baseDomain = listing.hostname.replace('www.', '');
    if (!parsed.hostname.includes(baseDomain)) return false;

    const path = parsed.pathname.toLowerCase();

    // Excluir extensiones de archivo
    if (/\.(pdf|jpg|jpeg|png|gif|svg|css|js|xml|zip|doc|docx)(\?|$)/i.test(path)) return false;

    // Excluir paths de navegación conocidos
    if (NAV_EXCLUSIONS.some((exc) => path.includes(exc.toLowerCase()))) return false;

    // El path debe tener cierta profundidad (al menos 2 segmentos no vacíos)
    const segments = path.split('/').filter(Boolean);
    if (segments.length < 2) return false;

    // El último segmento debe tener al menos 8 chars (slugs cortos suelen ser nav)
    const lastSegment = segments[segments.length - 1];
    if (lastSegment.length < 8) return false;

    // Señales positivas: palabras clave en el path
    const positiveSignals = [
      '/actividad/', '/evento/', '/taller/', '/programa/', '/concierto/',
      '/exposicion/', '/exposiciones/', '/agenda/', '/funcion/', '/obra/',
      '/espectaculo/', '/cine/', '/pelicula/', '/funcion/', '/encuentro/',
      '/programate/', '/eventos/', '/film/',
    ];
    const hasPositiveSignal = positiveSignals.some((s) => path.includes(s));

    // Si tiene señal positiva → incluir siempre
    if (hasPositiveSignal) return true;

    // Sin señal positiva → incluir solo si el path es suficientemente específico (slug largo)
    const fullPath = parsed.href;
    if (fullPath.length < 55) return false;

    return true;
  } catch {
    return false;
  }
}

// ── Extracción de links con Cheerio (rápido, sin JS) ─────────────────────────

async function fetchLinksCheerio(url: string): Promise<string[]> {
  const res = await fetch(url, {
    headers: {
      'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/120.0.0.0',
      'Accept-Language': 'es-CO,es;q=0.9',
    },
    signal: AbortSignal.timeout(15_000),
  });
  const html = await res.text();
  const $ = cheerio.load(html);
  const links: string[] = [];
  $('a[href]').each((_, el) => {
    const href = $(el).attr('href') ?? '';
    try {
      const abs = new URL(href, url).href;
      links.push(abs);
    } catch { /* skip malformed */ }
  });
  return [...new Set(links)];
}

// ── Extracción de links con Playwright (SPA / JS-rendered) ───────────────────

async function fetchLinksPlaywright(url: string, browser: Browser): Promise<string[]> {
  const context = await browser.newContext({
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/122.0.0.0 Safari/537.36',
    locale: 'es-CO',
    timezoneId: 'America/Bogota',
  });
  const page = await context.newPage();
  try {
    await page.goto(url, { waitUntil: 'networkidle', timeout: 30_000 });
    await page.waitForTimeout(2500);
    const links = await page.$$eval('a[href]', (anchors) =>
      (anchors as HTMLAnchorElement[]).map((a) => a.href).filter(Boolean)
    );
    return [...new Set(links)];
  } finally {
    await page.close();
    await context.close();
  }
}

// ── Auditar una sola fuente ───────────────────────────────────────────────────

async function auditSource(
  source: AuditSource,
  cache: ScrapingCache,
  browser: Browser,
  fastMode: boolean
): Promise<AuditResult> {
  const start = Date.now();
  const domain = new URL(source.url).hostname.replace('www.', '');

  try {
    // Sincronizar caché desde BD para este dominio
    await cache.syncFromDb(domain);

    // Extraer links del listing
    let allLinks: string[];
    try {
      allLinks = fastMode
        ? await fetchLinksCheerio(source.url)
        : await fetchLinksPlaywright(source.url, browser);
    } catch (err: unknown) {
      // Si Playwright falla (SPA), intentar Cheerio como fallback
      if (!fastMode) {
        try {
          allLinks = await fetchLinksCheerio(source.url);
        } catch {
          throw err;
        }
      } else {
        throw err;
      }
    }

    // Filtrar: solo links que parezcan actividades
    const activityLinks = [...new Set(allLinks)].filter((href) =>
      isActivityLike(href, source.url)
    );

    // Comparar con caché
    const cached = activityLinks.filter((url) => cache.has(url));
    const newUrls = activityLinks.filter((url) => !cache.has(url));

    return {
      name: source.name,
      url: source.url,
      status: 'ok',
      totalLinks: activityLinks.length,
      cached: cached.length,
      newLinks: newUrls.length,
      newUrls: newUrls.slice(0, 10),
      durationMs: Date.now() - start,
    };
  } catch (err: unknown) {
    const isTimeout = getErrorMessage(err)?.includes('timeout') || getErrorMessage(err)?.includes('ETIMEDOUT');
    return {
      name: source.name,
      url: source.url,
      status: isTimeout ? 'timeout' : 'error',
      totalLinks: 0,
      cached: 0,
      newLinks: 0,
      newUrls: [],
      error: getErrorMessage(err)?.slice(0, 120),
      durationMs: Date.now() - start,
    };
  }
}

// ── Obtener modo del scheduler para cada fuente ───────────────────────────────

async function getSchedulerModes(sources: AuditSource[]): Promise<Map<string, { mode: string; maxUrls: number }>> {
  const result = new Map<string, { mode: string; maxUrls: number }>();
  try {
    const healthData = await prisma.sourceHealth.findMany({ select: { source: true, score: true } });
    const healthDict: Record<string, number> = {};
    for (const h of healthData) healthDict[h.source] = h.score;

    const ctrMap = await getCTRByDomain();
    const dummyCache = new ScrapingCache();

    const inputs: { source: any; stats: SourceStats }[] = [];
    for (const s of sources) {
      const host = new URL(s.url).hostname.replace('www.', '');
      const { saveRate, avgCost } = await getSourceAggregatedStats(host, 5);
      const ctr = (ctrMap as Record<string, number>)[host] ?? 0;
      const score = healthDict[host] ?? 0.5;
      dummyCache.setSource(host);
      await dummyCache.syncFromDb(host);
      const reparseUrls = dummyCache.getReparseUrlsByDomain(host);

      inputs.push({
        source: { name: s.name, channel: 'web' as const, url: s.url, cityName: s.cityName, verticalSlug: 'kids' },
        stats: {
          sourceId: host,
          ctr7d: ctr,
          saveRate,
          health: score,
          avgCost,
          reparseCount: reparseUrls.length,
          isGov: host.includes('.gov.co'),
        },
      });
    }

    const plan = buildPredictivePlan(inputs, 300);
    for (const item of plan.planned) {
      result.set(item.source.name, { mode: item.mode, maxUrls: item.maxUrls });
    }
    for (const item of plan.skipped) {
      result.set(item.source.name, { mode: 'SKIPPED', maxUrls: 0 });
    }
  } catch (err: unknown) {
    console.warn(`⚠️  No se pudo consultar el scheduler: ${getErrorMessage(err)?.slice(0, 80)}`);
  }
  return result;
}

// ── Formateo de tabla ─────────────────────────────────────────────────────────

function pad(str: string, len: number): string {
  return str.length >= len ? str.slice(0, len) : str + ' '.repeat(len - str.length);
}

function formatDuration(ms: number): string {
  return ms < 1000 ? `${ms}ms` : `${(ms / 1000).toFixed(1)}s`;
}

// ── Main ──────────────────────────────────────────────────────────────────────

async function main() {
  const args = process.argv.slice(2);
  const fastMode = args.includes('--fast');
  const sourceFilter = args.find((a) => a.startsWith('--source='))?.split('=')[1]?.toLowerCase();

  const sources = sourceFilter
    ? SOURCES.filter((s) => s.name.toLowerCase().includes(sourceFilter))
    : SOURCES;

  if (sources.length === 0) {
    console.error(`❌ Ninguna fuente coincide con: ${sourceFilter}`);
    process.exit(1);
  }

  console.log(`\n${'═'.repeat(70)}`);
  console.log(`🔍 AUDITORÍA DE COBERTURA — ${new Date().toISOString().slice(0, 10)}`);
  console.log(`   Fuentes a auditar: ${sources.length} | Modo: ${fastMode ? 'FAST (Cheerio)' : 'FULL (Playwright)'}`);
  console.log(`${'═'.repeat(70)}\n`);

  // Cargar scheduler modes en paralelo con la inicialización del cache
  const cache = new ScrapingCache();
  const [schedulerModes] = await Promise.all([
    getSchedulerModes(sources),
  ]);

  // Lanzar browser (una sola instancia para todas las fuentes)
  const browser = fastMode ? null : await chromium.launch({ headless: true });

  const results: AuditResult[] = [];

  for (const source of sources) {
    process.stdout.write(`  ⏳ ${pad(source.name, 28)} `);
    const result = await auditSource(source, cache, browser!, fastMode);

    // Enriquecer con modo scheduler
    const sched = schedulerModes.get(source.name);
    if (sched) {
      result.schedulerMode = sched.mode;
      result.schedulerBudget = sched.maxUrls;
    }

    results.push(result);

    // Status inline
    if (result.status === 'ok') {
      const alert = result.newLinks > (result.schedulerBudget ?? 5) ? ' ⚠️' : '';
      process.stdout.write(
        `✅ ${result.totalLinks} en listing | ${result.cached} cacheados | 🆕 ${result.newLinks} nuevos (${formatDuration(result.durationMs)})${alert}\n`
      );
    } else {
      process.stdout.write(`${result.status === 'timeout' ? '⏱️ TIMEOUT' : '❌ ERROR'} — ${result.error?.slice(0, 60)}\n`);
    }
  }

  if (browser) await browser.close();

  // ── Tabla resumen ────────────────────────────────────────────────────────────
  console.log(`\n${'─'.repeat(95)}`);
  console.log(
    pad('Fuente', 28) +
    pad('Listing', 9) +
    pad('Cacheados', 11) +
    pad('🆕 Nuevos', 11) +
    pad('Scheduler', 16) +
    'Alerta'
  );
  console.log(`${'─'.repeat(95)}`);

  const sorted = [...results].sort((a, b) => b.newLinks - a.newLinks);

  for (const r of sorted) {
    if (r.status !== 'ok') {
      console.log(
        pad(r.name, 28) +
        pad('–', 9) + pad('–', 11) + pad('–', 11) +
        pad('–', 16) +
        `${r.status === 'timeout' ? '⏱️ TIMEOUT' : '❌ ERROR'}`
      );
      continue;
    }

    const schedLabel = r.schedulerMode
      ? `${r.schedulerMode} (${r.schedulerBudget})`
      : '?';

    let alert = '';
    if (r.schedulerBudget !== undefined && r.newLinks > r.schedulerBudget) {
      alert = `🔴 Budget insuficiente (necesita ≥${r.newLinks})`;
    } else if (r.newLinks > 0) {
      alert = '🟡 Hay contenido nuevo';
    } else {
      alert = '✅ Al día';
    }

    console.log(
      pad(r.name, 28) +
      pad(String(r.totalLinks), 9) +
      pad(String(r.cached), 11) +
      pad(String(r.newLinks), 11) +
      pad(schedLabel, 16) +
      alert
    );
  }

  // ── Detalle de URLs nuevas (solo fuentes con nuevos) ─────────────────────────
  const withNew = sorted.filter((r) => r.status === 'ok' && r.newLinks > 0);
  if (withNew.length > 0) {
    console.log(`\n${'─'.repeat(70)}`);
    console.log('📋 DETALLE DE URLs NUEVAS (top 10 por fuente)');
    console.log(`${'─'.repeat(70)}`);
    for (const r of withNew) {
      console.log(`\n${r.name} (${r.newLinks} nuevas):`);
      for (const url of r.newUrls) {
        const shortUrl = url.replace(/^https?:\/\/(www\.)?[^/]+/, '');
        console.log(`  🆕 ${shortUrl}`);
      }
      if (r.newLinks > 10) {
        console.log(`  ... y ${r.newLinks - 10} más`);
      }
    }
  }

  // ── Recomendación final ───────────────────────────────────────────────────────
  const critical = sorted.filter(
    (r) => r.status === 'ok' && r.schedulerBudget !== undefined && r.newLinks > r.schedulerBudget
  );

  console.log(`\n${'═'.repeat(70)}`);
  if (critical.length > 0) {
    console.log('⚠️  ACCIÓN REQUERIDA — Fuentes con budget insuficiente:');
    for (const r of critical) {
      console.log(`   • ${r.name}: ${r.newLinks} nuevas, budget actual ${r.schedulerBudget} → subir a ≥${r.newLinks}`);
    }
  } else {
    console.log('✅ Todos los budgets del scheduler cubren el tamaño real del listing.');
  }
  console.log(`${'═'.repeat(70)}\n`);

  await prisma.$disconnect();
}

main().catch((err) => {
  console.error('Fatal:', err);
  process.exit(1);
});

/**
 * backfill-descriptions.ts
 *
 * Pipeline de reescritura segura de descripciones legacy.
 * Principio rector: si el contenido puede estructurarse → NO usar IA.
 *
 * Etapas:
 *   1. Normalización (limpieza de texto)
 *   2. Detección de estructura (regex, sin IA)
 *   3. Generación estructurada (sin IA)
 *   4. Fallback rule-based (primera frase limpia, sin IA)
 *   5. IA solo en edge cases (texto largo + ambiguo)
 *
 * Uso:
 *   npx tsx scripts/backfill-descriptions.ts [--dry-run] [--limit=N] [--ai-enabled]
 *
 * Flags:
 *   --dry-run      Muestra qué haría sin guardar en BD
 *   --limit=N      Procesar solo N actividades (útil para pruebas)
 *   --ai-enabled   Habilita la etapa de IA (por defecto desactivada para conservar cuota)
 */

import 'dotenv/config';
import { PrismaClient } from '../src/generated/prisma/client';
import { PrismaPg } from '@prisma/adapter-pg';
import { GoogleGenerativeAI } from '@google/generative-ai';
import { getAdaptiveRules, getSourceRules } from '@/modules/scraping/adaptive-rules';
import { ambiguityScore } from '@/modules/scraping/ambiguity';
import { getSystemStatus } from '@/modules/scraping/alerts';

// =============================================================================
// Setup
// =============================================================================

const adapter = new PrismaPg({ connectionString: process.env.DATABASE_URL! });
const prisma = new PrismaClient({ adapter });

const dryRun = process.argv.includes('--dry-run');
const aiEnabled = process.argv.includes('--ai-enabled');
const limitArg = process.argv.find((a) => a.startsWith('--limit='));
const limit = limitArg ? parseInt(limitArg.split('=')[1], 10) : undefined;

type Method = 'structured' | 'rule-based' | 'ai' | 'skipped';

interface Result {
  id: string;
  title: string;
  originalDescription: string;
  newDescription: string;
  method: Method;
  charsBefore: number;
  charsAfter: number;
}

// =============================================================================
// ETAPA 1 — Normalización
// =============================================================================

const PROMOTIONAL_PHRASES = [
  /te invitamos a/gi,
  /no te pierdas/gi,
  /ven a disfrutar/gi,
  /no te lo pierdas/gi,
  /anímate a/gi,
  /no faltes/gi,
  /inscríbete ya/gi,
  /cupos limitados/gi,
  /¡inscríbete!/gi,
  /¡no te lo pierdas!/gi,
];

function normalize(text: string): string {
  let t = text.replace(/[\r\n\t]+/g, ' ');
  for (const phrase of PROMOTIONAL_PHRASES) {
    t = t.replace(phrase, '');
  }
  return t.replace(/\s+/g, ' ').trim();
}

// =============================================================================
// ETAPA 2 — Detección de estructura
// =============================================================================

const TIPO_KEYWORDS = /\b(taller|curso|clase|evento|club|campamento|festival|ciclo|conferencia|obra|exposición|exposicion|concierto|recital|feria|muestra|seminario|diplomado|programa|actividad)\b/i;
const TEMA_KEYWORDS = /\b(arte|música|musica|danza|teatro|robótica|robotica|ciencia|lectura|escritura|cine|cocina|inglés|ingles|ajedrez|yoga|fotografía|fotografia|manualidades|pintura|dibujo|escultura|títeres|titeres|circo|acrobacia|natación|natacion|fútbol|futbol|baloncesto|atletismo|ecosistema|naturaleza|jardín|jardin|programación|programacion|animación|animacion)\b/i;
const PUBLICO_KEYWORDS = /\b(niños|niñas|niños y niñas|ninos|adolescentes|jóvenes|jovenes|familias|adultos|bebés|bebes|primera infancia|infantes|infantil|infantiles|toda la familia|público general)\b/i;

interface Parsed {
  tipo: string;
  tema: string;
  publico?: string;
}

function canParseStructured(text: string): boolean {
  return TIPO_KEYWORDS.test(text) && TEMA_KEYWORDS.test(text);
}

function parseStructured(text: string): Parsed | null {
  const tipoMatch = text.match(TIPO_KEYWORDS);
  const temaMatch = text.match(TEMA_KEYWORDS);
  if (!tipoMatch || !temaMatch) return null;

  const publicoMatch = text.match(PUBLICO_KEYWORDS);

  return {
    tipo: normalize(tipoMatch[0]).toLowerCase(),
    tema: normalize(temaMatch[0]).toLowerCase(),
    publico: publicoMatch ? normalize(publicoMatch[0]).toLowerCase() : undefined,
  };
}

// =============================================================================
// ETAPA 3+4 — Generación sin IA
// =============================================================================

function buildDescription(p: Parsed): string {
  const base = `${capitalize(p.tipo)} de ${p.tema}`;
  return p.publico ? `${base} dirigido a ${p.publico}.` : `${base}.`;
}

function capitalize(s: string): string {
  return s.charAt(0).toUpperCase() + s.slice(1);
}

// =============================================================================
// ETAPA 5 — Rule-based fallback
// =============================================================================

function safeRewrite(text: string): string {
  // Toma la primera oración completa y la limpia
  const firstSentence = text.split(/[.!?]/)[0] ?? text;
  let clean = firstSentence;
  for (const phrase of PROMOTIONAL_PHRASES) {
    clean = clean.replace(phrase, '');
  }
  return clean.replace(/\s+/g, ' ').trim();
}

function isGoodEnough(text: string): boolean {
  return text.length >= 40 && text.length <= 200;
}

// =============================================================================
// ETAPA 6 — IA como último recurso
// =============================================================================

const MAX_RETRIES = 3;
const RETRY_BASE_MS = 2000;
let lastGeminiCall = 0;
const MIN_INTERVAL_MS = 12000; // 5 RPM

async function aiRewrite(text: string, genAI: GoogleGenerativeAI): Promise<string> {
  // Rate limit
  const now = Date.now();
  const wait = MIN_INTERVAL_MS - (now - lastGeminiCall);
  if (wait > 0) {
    console.log(`   ⏳ Rate limit: esperando ${(wait / 1000).toFixed(1)}s...`);
    await new Promise((r) => setTimeout(r, wait));
  }
  lastGeminiCall = Date.now();

  const model = genAI.getGenerativeModel({
    model: 'gemini-2.5-flash',
    generationConfig: { temperature: 0.1, maxOutputTokens: 256 },
  });

  const prompt = `Reescribe el siguiente texto en UNA SOLA frase clara, informativa y sin tono promocional.
No agregues información que no esté en el texto. Sin adjetivos exagerados. Máximo 160 caracteres.

TEXTO: ${text.substring(0, 500)}

Responde SOLO con la frase reescrita, sin comillas ni explicaciones.`;

  for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
    try {
      const result = await model.generateContent(prompt);
      const raw = result.response.text().trim().replace(/^["']|["']$/g, '');
      return raw.substring(0, 160);
    } catch (err: unknown) {
      const error = err as { status?: number; message?: string };
      const status = error?.status ?? 0;
      if ((status === 429 || status === 503) && attempt < MAX_RETRIES) {
        const delay = RETRY_BASE_MS * Math.pow(2, attempt - 1);
        console.log(`   ⚠️  Gemini ${status} (intento ${attempt}/${MAX_RETRIES}). Reintentando en ${delay}ms...`);
        await new Promise((r) => setTimeout(r, delay));
        continue;
      }
      throw err;
    }
  }
  throw new Error('Agotados reintentos Gemini');
}

// =============================================================================
// PIPELINE PRINCIPAL
// =============================================================================

async function processActivity(
  activity: { id: string; title: string; description: string; sourceUrl: string },
  genAI: GoogleGenerativeAI | null,
  finalRules: { forceStructured: boolean; minDescriptionLength: number }
): Promise<Result> {
  const original = activity.description ?? '';
  const charsBefore = original.length;

  // Skip si la descripción ya es corta y limpia (≤ 160 chars sin frases promocionales)
  const normalized = normalize(original);
  if (normalized.length <= 160 && !PROMOTIONAL_PHRASES.some((p) => p.test(original))) {
    return {
      id: activity.id, title: activity.title,
      originalDescription: original, newDescription: original,
      method: 'skipped', charsBefore, charsAfter: original.length,
    };
  }

  // Etapa 2+3+4: Detección y generación estructurada vs Rule-based
  const fallback = safeRewrite(normalized);
  const ambiguity = ambiguityScore(normalized);

  // structured gana si la ambigüedad es alta O si la regla adaptativa lo fuerza
  if ((ambiguity >= 2 || finalRules.forceStructured) && canParseStructured(normalized)) {
    const parsed = parseStructured(normalized);
    if (parsed) {
      const structuredDesc = buildDescription(parsed);
      if (structuredDesc.length >= 20) {
        return {
          id: activity.id, title: activity.title,
          originalDescription: original, newDescription: structuredDesc,
          method: 'structured', charsBefore, charsAfter: structuredDesc.length,
        };
      }
    }
  }

  // Etapa 5: Rule-based fallback (si es lo suficientemente bueno)
  if (isGoodEnough(fallback)) {
    return {
      id: activity.id, title: activity.title,
      originalDescription: original, newDescription: fallback,
      method: 'rule-based', charsBefore, charsAfter: fallback.length,
    };
  }

  // fallback final a structured (si aplica, para evitar deshechar texto útil)
  if (canParseStructured(normalized)) {
    const parsed = parseStructured(normalized);
    if (parsed) {
      const structuredDesc = buildDescription(parsed);
      if (structuredDesc.length >= 20) {
        return {
          id: activity.id, title: activity.title,
          originalDescription: original, newDescription: structuredDesc,
          method: 'structured', charsBefore, charsAfter: structuredDesc.length,
        };
      }
    }
  }

  // Etapa 6: IA solo si está habilitada y el fallback fue insuficiente
  if (aiEnabled && genAI && normalized.length > 300) {
    try {
      const aiDesc = await aiRewrite(normalized, genAI);
      return {
        id: activity.id, title: activity.title,
        originalDescription: original, newDescription: aiDesc,
        method: 'ai', charsBefore, charsAfter: aiDesc.length,
      };
    } catch {
      console.log(`   ❌ AI falló para activity ${activity.id} — usando fallback rule-based`);
    }
  }

  // Si el fallback es demasiado corto pero es lo mejor que tenemos → rule-based igual
  // Nota: La validación final real de `finalRules.minDescriptionLength` se ejecuta en main()
  const safeFallback = fallback.length >= 10 ? fallback : normalized.substring(0, 160).trim();
  return {
    id: activity.id, title: activity.title,
    originalDescription: original, newDescription: safeFallback,
    method: 'rule-based', charsBefore, charsAfter: safeFallback.length,
  };
}

// =============================================================================
// MAIN
// =============================================================================

async function main() {
  console.log('\n✍️  Backfill de Descripciones — HabitaPlan');
  console.log(`Modo:        ${dryRun ? '🔍 DRY RUN (sin guardar)' : '💾 GUARDAR EN BD'}`);
  console.log(`IA habilitada: ${aiEnabled ? '✅ Sí (conserva cuota)' : '❌ No (--ai-enabled para activar)'}`);
  console.log(`Límite:      ${limit ?? 'todas las actividades'}\n`);

  // Agrega esquema si no existe (idempotente, evita problemas de PgBouncer con prisma migrate)
  if (!dryRun) {
    try {
      await prisma.$executeRaw`
        ALTER TABLE activities
        ADD COLUMN IF NOT EXISTS description_method TEXT DEFAULT NULL
      `;
      console.log('✅ Columna description_method verificada/creada');

      await prisma.$executeRaw`
        CREATE TABLE IF NOT EXISTS content_quality_metrics (
          id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
          created_at TIMESTAMP DEFAULT now(),
          avg_length INT NOT NULL,
          pct_short FLOAT NOT NULL,
          pct_noise FLOAT NOT NULL,
          pct_promo FLOAT NOT NULL,
          total_processed INT NOT NULL,
          source TEXT,
          pipeline_stage TEXT
        )
      `;
      // Alter table por si la tabla ya existía sin estas columnas
      await prisma.$executeRaw`
        ALTER TABLE content_quality_metrics
        ADD COLUMN IF NOT EXISTS source TEXT,
        ADD COLUMN IF NOT EXISTS pipeline_stage TEXT
      `;
      console.log('✅ Tabla content_quality_metrics verificada/creada\n');
    } catch (err) {
      console.log('ℹ️  Configuración de DDL inicializada\n');
    }
  }

  // Cargar actividades ACTIVE + PAUSED (las que se muestran al usuario)
  const activities = await prisma.activity.findMany({
    where: { status: { in: ['ACTIVE', 'PAUSED'] } },
    select: { id: true, title: true, description: true, sourceUrl: true },
    orderBy: { createdAt: 'asc' },
    ...(limit ? { take: limit } : {}),
  });

  console.log(`📦 Actividades a procesar: ${activities.length}\n`);

  // Extraer Lógica Adaptativa (Capa 1: Global metrics & Capa 2: Source Health cache map)
  const latestMetrics = await prisma.contentQualityMetric.findFirst({
    orderBy: { createdAt: 'desc' }
  });
  const adaptiveRules = getAdaptiveRules(latestMetrics as any);

  const sourceHealthMap = new Map<string, number | null>();
  const allHealths = await prisma.sourceHealth.findMany();
  for (const h of allHealths) {
    sourceHealthMap.set(h.source, h.score);
  }

  // Inicializar Gemini (opcional)
  const apiKey = process.env.GOOGLE_AI_STUDIO_KEY ?? '';
  const genAI = apiKey && aiEnabled ? new GoogleGenerativeAI(apiKey) : null;

  let sumMinLength = 0;
  const results: Result[] = [];
  const stats: Record<Method, number> = { structured: 0, 'rule-based': 0, ai: 0, skipped: 0 };

  for (const activity of activities) {
    process.stdout.write(`⟳ [${results.length + 1}/${activities.length}] ${activity.title.substring(0, 60)}... `);

    // Identificar dominio para Capa 2
    let domain = 'unknown';
    if (activity.sourceUrl) {
      try { domain = new URL(activity.sourceUrl).hostname.replace('www.', ''); } catch(e) {}
    }
    const sourceScore = sourceHealthMap.get(domain);
    const sourceRules = getSourceRules(sourceScore);

    // Crossover para Reglas Finales de Extracción (Prioridad fuente)
    const finalRules = {
      forceStructured: sourceRules.forceStructured || adaptiveRules.forceStructured,
      minDescriptionLength: Math.max(
        adaptiveRules.minDescriptionLength,
        sourceRules.minDescriptionLength
      )
    };
    sumMinLength += finalRules.minDescriptionLength;

    console.info(JSON.stringify({
      event: "adaptive_rules_applied",
      source: domain,
      score: sourceScore,
      pctShort: latestMetrics?.pctShort,
      pctNoise: latestMetrics?.pctNoise,
      rules: finalRules,
    }));

    const result = await processActivity({ ...activity, sourceUrl: activity.sourceUrl ?? '' }, genAI, finalRules);

    // Validación Final Estricta: si queda por debajo de las rules adaptativas de su dominio/entorno, se descarta estrepitosamente.
    if (result.method !== 'skipped' && result.newDescription.length < finalRules.minDescriptionLength) {
      console.log(`   🚨 descartado orgánicamente: no cumplió threshold dinámico de ${finalRules.minDescriptionLength} chars`);
      result.method = 'skipped';
      result.newDescription = result.originalDescription;
      result.charsAfter = result.newDescription.length;
    }

    results.push(result);
    stats[result.method]++;

    const methodEmoji: Record<Method, string> = {
      structured: '🏗️ structured',
      'rule-based': '📏 rule-based',
      ai: '🤖 ai',
      skipped: '⏭️ skipped',
    };
    console.log(methodEmoji[result.method]);

    if (result.method !== 'skipped') {
      console.log(`   Antes (${result.charsBefore}): ${result.originalDescription.substring(0, 80)}...`);
      console.log(`   Después (${result.charsAfter}): ${result.newDescription}`);
    }

    // Guardar en BD si no es dry-run
    if (!dryRun && result.method !== 'skipped') {
      // Usamos $executeRaw solo para el campo description_method (no en schema Prisma)
      // Para description usamos el ORM para respetar updatedAt automático
      await prisma.activity.update({
        where: { id: result.id },
        data: { description: result.newDescription },
      });
      // Actualizar description_method via raw (campo fuera del schema)
      await prisma.$executeRaw`
        UPDATE activities
        SET description_method = ${result.method}
        WHERE id = ${result.id}
      `;
    }
  }

  // =============================================================================
  // RESUMEN FINAL
  // =============================================================================
  const processed = activities.length - stats.skipped;
  const pct = (n: number) => processed > 0 ? `${((n / processed) * 100).toFixed(1)}%` : '0%';
  const withoutAI = stats.structured + stats['rule-based'];

  console.log('\n════════════════════════════════════════');
  console.log('📊 RESUMEN FINAL');
  console.log('════════════════════════════════════════');
  console.log(`Total actividades:   ${activities.length}`);
  console.log(`Procesadas:          ${processed}`);
  console.log(`Omitidas (ya ok):    ${stats.skipped}`);
  console.log('');
  console.log(`🏗️  Structured:      ${stats.structured} (${pct(stats.structured)} de procesadas)`);
  console.log(`📏 Rule-based:       ${stats['rule-based']} (${pct(stats['rule-based'])} de procesadas)`);
  console.log(`🤖 AI:               ${stats.ai} (${pct(stats.ai)} de procesadas)`);
  console.log('');
  console.log(`✅ Sin IA:           ${withoutAI} (${pct(withoutAI)}) — objetivo ≥ 80%`);
  console.log(`${parseFloat(pct(withoutAI)) >= 80 ? '🎯 OBJETIVO CUMPLIDO' : '⚠️  Por debajo del objetivo (80%)'}`);

  const computedDiscardRate = activities.length > 0 ? Number((stats.skipped / activities.length).toFixed(4)) : 0;
  const computedAvgLength = activities.length > 0 ? Math.round(sumMinLength / activities.length) : 0;

  console.info(JSON.stringify({
    event: "adaptive_filter_summary",
    totalProcessed: activities.length,
    totalSkipped: stats.skipped,
    discardRate: computedDiscardRate,
    avgMinLength: computedAvgLength,
    timestamp: new Date().toISOString()
  }));

  const status = getSystemStatus({
    discardRate: computedDiscardRate,
    avgLength: computedAvgLength
  });

  console.info(JSON.stringify({
    event: "system_health_alert",
    level: "info",
    status,
    discardRate: computedDiscardRate,
    avgLength: computedAvgLength,
    timestamp: new Date().toISOString()
  }));

  if (status !== "healthy") {
    console.warn(JSON.stringify({
      event: "system_health_alert",
      level: "warning",
      status,
      discardRate: computedDiscardRate,
      avgLength: computedAvgLength,
      timestamp: new Date().toISOString()
    }));
  }

  // =============================================================================
  // SEÑALES DE OBSERVABILIDAD — activan ambiguityScore si 2+ disparan
  // Señal 2 se evalúa sobre originalDescription (no el reescrito)
  // para detectar suciedad en la fuente, no en el output
  // =============================================================================
  const processedResults = results.filter((r) => r.method !== 'skipped');

  if (processedResults.length > 0) {
    const avgLength = processedResults.reduce((acc, r) => acc + r.charsAfter, 0) / processedResults.length;
    const shortDescs = processedResults.filter((r) => r.charsAfter < 60).length;
    const noisySource = processedResults.filter((r) => /[#@]|https?:\/\/|[A-Z]{4,}/.test(r.originalDescription)).length;
    const promoStart = processedResults.filter((r) => /^(te invitamos|no te pierdas|ven)/i.test(r.originalDescription)).length;
    const pctShort = (shortDescs / processedResults.length) * 100;
    const pctNoisy = (noisySource / processedResults.length) * 100;
    const pctPromo = (promoStart / processedResults.length) * 100;

    console.log('\n────────────────────────────────────────');
    console.log('🔭 OBSERVABILIDAD (señales de calidad)');
    console.log('────────────────────────────────────────');
    console.log(`📏 Avg length output:    ${Math.round(avgLength)} chars`);
    console.log(`📉 Señal 1 — cortas (<60):  ${shortDescs} (${pctShort.toFixed(1)}%) ${pctShort > 20 ? '⚠️  ALERTA: umbral > 20%' : '🟢 ok'}`);
    console.log(`🔊 Señal 2 — ruido fuente:  ${noisySource} (${pctNoisy.toFixed(1)}%) ${pctNoisy > 15 ? '⚠️  ALERTA: umbral > 15%' : '🟢 ok'}`);
    console.log(`📣 Señal 3 — promo (canary): ${promoStart} (${pctPromo.toFixed(1)}%) ${pctPromo > 25 ? '🚨 ALERTA: normalize puede estar fallando' : '🟢 ok'}`);

    const alertCount = [pctShort > 20, pctNoisy > 15, pctPromo > 25].filter(Boolean).length;
    if (alertCount >= 2) {
      console.log('\n🚨 ≥2 señales activas → considerar activar ambiguityScore');
    } else {
      console.log('\n✅ Pipeline óptimo — sin necesidad de ambiguityScore');
    }
  }


  if (dryRun) {
    console.log('\n⚠️  Modo DRY RUN — ningún cambio fue guardado en BD');
    console.log('   Ejecuta sin --dry-run para aplicar los cambios\n');
  } else {
    console.log(`\n✨ ${processed} actividades actualizadas en BD`);

    // Guardar métricas en DB
    if (processedResults.length > 0) {
      try {
        const avgLength = processedResults.reduce((acc, r) => acc + r.charsAfter, 0) / processedResults.length;
        const shortDescs = processedResults.filter((r) => r.charsAfter < 60).length;
        const noisySource = processedResults.filter((r) => /[#@]|https?:\/\/|[A-Z]{4,}/.test(r.originalDescription)).length;
        const promoStart = processedResults.filter((r) => /^(te invitamos|no te pierdas|ven)/i.test(r.originalDescription)).length;

        await prisma.contentQualityMetric.create({
          data: {
            avgLength: Math.round(avgLength),
            pctShort: (shortDescs / processedResults.length) * 100,
            pctNoise: (noisySource / processedResults.length) * 100,
            pctPromo: (promoStart / processedResults.length) * 100,
            totalProcessed: processedResults.length,
            source: 'backfill',
            pipelineStage: 'backfill',
          }
        });
        console.log('✅ Métricas de calidad guardadas en histórico\n');
      } catch (err) {
        console.error('⚠️  No se pudieron guardar las métricas de calidad:', err);
      }
    } else {
      console.log();
    }
  }

  await prisma.$disconnect();
}

main().catch((err) => {
  console.error('\n❌ Error fatal:', err);
  process.exit(1);
});

#!/usr/bin/env npx tsx
import { getErrorMessage } from '../src/lib/error';
/**
 * Benchmark: CHUNK_SIZE 50 vs 100 vs 200 en Gemini discoverActivityLinks
 * Fuente de prueba: Banrep Ibagué (causa original del problema de JSON inválido)
 *
 * Ejecutar: npx tsx scripts/benchmark-chunk-size.ts [--chunk=100] [--dry-run]
 *
 * Consumo estimado de cuota Gemini (free tier 20 req/día):
 *   chunk=50:  ~3 lotes = 3 llamadas
 *   chunk=100: ~2 lotes = 2 llamadas
 *   chunk=200: ~1 lote  = 1 llamada
 *
 * Para benchmark completo (3 tamaños):
 *   npx tsx scripts/benchmark-chunk-size.ts  → usa ~6-8 llamadas
 */

import 'dotenv/config';
import * as https from 'https';
import { GoogleGenerativeAI } from '@google/generative-ai';
import { preFilterUrls } from '../src/lib/url-classifier';

// ── Config ─────────────────────────────────────────────────────────────────
const args = process.argv.slice(2);
const dryRun = args.includes('--dry-run');
const singleChunk = args.find((a) => a.startsWith('--chunk='))
  ? parseInt(args.find((a) => a.startsWith('--chunk='))!.split('=')[1]!)
  : null;

const CHUNK_SIZES = singleChunk ? [singleChunk] : [50, 100, 200];
const RATE_LIMIT_MS = 12_000; // 12s entre llamadas (5 RPM)
const SITEMAP_URL = 'https://www.banrepcultural.org/sitemap.xml';
const CITY_FILTER = '/ibague/';

// ── Tipos ──────────────────────────────────────────────────────────────────
interface BenchmarkResult {
  chunkSize: number;
  totalUrls: number;
  urlsAfterClassifier: number;
  classifierReduction: number;
  chunksCount: number;
  apiCalls: number;
  successCalls: number;
  jsonErrors: number;
  activitiesFound: number;
  durationMs: number;
}

// ── HTTP helper ────────────────────────────────────────────────────────────
function fetchXml(url: string): Promise<string> {
  return new Promise((resolve, reject) => {
    https
      .get(url, { headers: { 'User-Agent': 'HabitaPlan/1.0' } }, (res) => {
        let data = '';
        res.on('data', (chunk) => (data += chunk));
        res.on('end', () => resolve(data));
      })
      .on('error', reject);
  });
}

// ── Parsear sitemap XML paginado ───────────────────────────────────────────
async function parseSitemapUrls(baseUrl: string, filterPath: string): Promise<string[]> {
  const urls: string[] = [];

  // Primero revisar si tiene sub-sitemaps paginados
  const mainXml = await fetchXml(baseUrl);
  const subSitemaps = [...mainXml.matchAll(/<loc>(.*?)<\/loc>/g)]
    .map((m) => m[1].trim())
    .filter((u) => u.includes('sitemap.xml?page=') || u.includes('sitemap_'));

  if (subSitemaps.length > 0) {
    // Sitemap paginado: iterar cada página con delay
    for (const pageUrl of subSitemaps) {
      const pageXml = await fetchXml(pageUrl);
      const pageUrls = [...pageXml.matchAll(/<loc>(.*?)<\/loc>/g)]
        .map((m) => m[1].trim())
        .filter((u) => u.includes(filterPath));
      urls.push(...pageUrls);
      await new Promise((r) => setTimeout(r, 800)); // Rate limit: 0.8s entre páginas
    }
  } else {
    // Sitemap simple
    const simpleUrls = [...mainXml.matchAll(/<loc>(.*?)<\/loc>/g)]
      .map((m) => m[1].trim())
      .filter((u) => u.includes(filterPath));
    urls.push(...simpleUrls);
  }

  return urls;
}

// ── Gemini discover links ──────────────────────────────────────────────────
async function discoverLinksWithChunk(
  links: Array<{ url: string; anchorText: string }>,
  chunkSize: number,
  genAI: GoogleGenerativeAI,
): Promise<{
  activitiesFound: number;
  apiCalls: number;
  successCalls: number;
  jsonErrors: number;
  durationMs: number;
}> {
  const model = genAI.getGenerativeModel({
    model: 'gemini-2.5-flash',
    generationConfig: {
      responseMimeType: 'application/json',
      temperature: 0.1,
      maxOutputTokens: 8192,
    },
  });

  const chunks: typeof links[] = [];
  for (let i = 0; i < links.length; i += chunkSize) {
    chunks.push(links.slice(i, i + chunkSize));
  }

  const allActivityUrls: string[] = [];
  let apiCalls = 0;
  let successCalls = 0;
  let jsonErrors = 0;
  const startTime = Date.now();
  let lastCallTime = 0;

  for (let idx = 0; idx < chunks.length; idx++) {
    const chunk = chunks[idx];

    // Rate limit enforcement
    const now = Date.now();
    const elapsed = now - lastCallTime;
    if (lastCallTime > 0 && elapsed < RATE_LIMIT_MS) {
      const waitMs = RATE_LIMIT_MS - elapsed;
      process.stdout.write(`  ⏳ Rate limit: esperando ${(waitMs / 1000).toFixed(1)}s...`);
      await new Promise((r) => setTimeout(r, waitMs));
      console.log(' OK');
    }

    const linksText = chunk
      .map((l, i) => `${i + 1}. URL: ${l.url} | Texto: ${l.anchorText}`)
      .join('\n');

    const prompt = `Selecciona SOLO los links a actividades, eventos, talleres o programas para niños/familias.
Excluye navegación general, políticas, páginas corporativas.
Responde con JSON: { "indices": [1, 3, 7, ...] }

LINKS:
${linksText}`;

    try {
      apiCalls++;
      lastCallTime = Date.now();
      const result = await model.generateContent(prompt);
      const rawText = result.response.text();
      const jsonStr = rawText
        .replace(/^```(?:json)?\s*/i, '')
        .replace(/\s*```\s*$/, '')
        .trim();

      let parsed: { indices?: number[] };
      try {
        parsed = JSON.parse(jsonStr);
      } catch (_) {
        jsonErrors++;
        console.log(`  ❌ Lote ${idx + 1}: JSON inválido (${jsonStr.substring(0, 80)}...)`);
        continue;
      }

      const indices = parsed.indices ?? [];
      const found = indices
        .filter((i) => i >= 1 && i <= chunk.length)
        .map((i) => chunk[i - 1].url);

      successCalls++;
      allActivityUrls.push(...found);
      console.log(
        `  ✅ Lote ${idx + 1}/${chunks.length}: ${found.length} actividades (${chunk.length} URLs enviadas)`,
      );
    } catch (err: unknown) {
      apiCalls++;
      jsonErrors++;
      console.log(`  ❌ Lote ${idx + 1}: Error API — ${getErrorMessage(err)?.substring(0, 80)}`);
    }
  }

  return {
    activitiesFound: allActivityUrls.length,
    apiCalls,
    successCalls,
    jsonErrors,
    durationMs: Date.now() - startTime,
  };
}

// ── MAIN ───────────────────────────────────────────────────────────────────
async function main() {
  console.log('\n' + '='.repeat(70));
  console.log('⚡ BENCHMARK: CHUNK_SIZE vs JSON Parsing Success Rate');
  console.log('='.repeat(70));
  console.log(`Fuente: Banrep Ibagué (${SITEMAP_URL})`);
  console.log(`Tamaños a probar: ${CHUNK_SIZES.join(', ')}`);
  console.log(`Dry-run: ${dryRun ? 'SÍ (sin Gemini)' : 'NO (usa cuota API)'}\n`);

  // 1. Fetch sitemap (paginado)
  console.log('📥 Descargando sitemap.xml de Banrep (puede tomar ~8s si paginado)...');
  const allUrls = await parseSitemapUrls(SITEMAP_URL, CITY_FILTER);
  console.log(`   → ${allUrls.length} URLs filtradas con "${CITY_FILTER}"`);

  if (allUrls.length === 0) {
    console.error('\n❌ No se encontraron URLs. Verifica conectividad o filtro de ciudad.');
    process.exit(1);
  }

  // 2. Aplicar URL classifier (Stage 2)
  console.log('\n🔍 Aplicando URL classifier (threshold=45)...');
  const classifierResult = preFilterUrls(allUrls, 45);
  const classifiedUrls = classifierResult.kept;

  console.log(`   → ${allUrls.length} originales → ${classifiedUrls.length} después del filtro`);
  console.log(
    `   → Reducción: ${classifierResult.stats.reductionPct}% (${classifierResult.stats.filtered} eliminadas)`,
  );

  // Convertir a formato DiscoveredLink
  const links = classifiedUrls.map((url) => ({
    url,
    anchorText: url.split('/').pop()?.replace(/-/g, ' ') ?? '',
  }));

  if (dryRun) {
    console.log('\n🔸 Dry-run: Simulando chunks sin llamar a Gemini...\n');
    const results: BenchmarkResult[] = CHUNK_SIZES.map((chunkSize) => {
      const chunksCount = Math.ceil(classifiedUrls.length / chunkSize);
      return {
        chunkSize,
        totalUrls: allUrls.length,
        urlsAfterClassifier: classifiedUrls.length,
        classifierReduction: classifierResult.stats.reductionPct,
        chunksCount,
        apiCalls: chunksCount,
        successCalls: Math.floor(chunksCount * 0.9), // simula 90% success
        jsonErrors: Math.ceil(chunksCount * 0.1),
        activitiesFound: 0,
        durationMs: chunksCount * RATE_LIMIT_MS,
      };
    });
    printReport(results, allUrls.length, classifiedUrls.length);
    return;
  }

  // 3. Verificar API key
  const apiKey = process.env.GOOGLE_AI_STUDIO_KEY;
  if (!apiKey) {
    console.error('\n❌ GOOGLE_AI_STUDIO_KEY no encontrada en .env');
    process.exit(1);
  }

  const genAI = new GoogleGenerativeAI(apiKey);
  const results: BenchmarkResult[] = [];

  // 4. Ejecutar benchmark para cada chunk size
  for (const chunkSize of CHUNK_SIZES) {
    const chunksCount = Math.ceil(classifiedUrls.length / chunkSize);
    console.log(
      `\n${'─'.repeat(60)}\n📦 Probando CHUNK_SIZE = ${chunkSize} (${chunksCount} lotes)`,
    );
    console.log('─'.repeat(60));

    const benchStart = Date.now();
    const result = await discoverLinksWithChunk(links, chunkSize, genAI);

    results.push({
      chunkSize,
      totalUrls: allUrls.length,
      urlsAfterClassifier: classifiedUrls.length,
      classifierReduction: classifierResult.stats.reductionPct,
      chunksCount,
      ...result,
      durationMs: Date.now() - benchStart,
    });
  }

  // 5. Reporte final
  printReport(results, allUrls.length, classifiedUrls.length);
}

function printReport(
  results: BenchmarkResult[],
  totalUrls: number,
  urlsAfterClassifier: number,
) {
  console.log('\n\n' + '='.repeat(70));
  console.log('📊 RESULTADOS DEL BENCHMARK');
  console.log('='.repeat(70));
  console.log(`\nFuente: Banrep Ibagué`);
  console.log(`URLs en sitemap: ${totalUrls}`);
  console.log(`URLs después del URL Classifier: ${urlsAfterClassifier}`);

  console.log('\n┌──────────┬──────────┬──────────┬──────────┬──────────┬──────────┐');
  console.log('│ Chunk    │ Lotes    │ API Calls│ Errores  │ Activid. │ Tiempo   │');
  console.log('├──────────┼──────────┼──────────┼──────────┼──────────┼──────────┤');

  for (const r of results) {
    const successRate =
      r.apiCalls > 0 ? ((r.successCalls / r.apiCalls) * 100).toFixed(0) + '%' : 'N/A';
    console.log(
      `│ ${String(r.chunkSize).padEnd(8)} │ ${String(r.chunksCount).padEnd(8)} │ ${String(r.apiCalls).padEnd(8)} │ ${(r.jsonErrors > 0 ? '⚠️ ' + r.jsonErrors : r.jsonErrors).toString().padEnd(8)} │ ${String(r.activitiesFound).padEnd(8)} │ ${((r.durationMs / 1000).toFixed(1) + 's').padEnd(8)} │`,
    );
  }
  console.log('└──────────┴──────────┴──────────┴──────────┴──────────┴──────────┘');

  // Análisis
  const bestResult = results
    .filter((r) => r.jsonErrors === 0)
    .sort((a, b) => b.activitiesFound - a.activitiesFound || a.apiCalls - b.apiCalls)[0];

  console.log('\n🔍 Análisis:');
  results.forEach((r) => {
    const successPct = r.apiCalls > 0 ? Math.round((r.successCalls / r.apiCalls) * 100) : 0;
    const label = r === bestResult ? ' ← GANADOR' : '';
    console.log(
      `   chunk=${r.chunkSize}: ${successPct}% éxito JSON, ${r.activitiesFound} actividades, ${r.jsonErrors} errores${label}`,
    );
  });

  if (bestResult) {
    console.log(`\n✅ Recomendación: CHUNK_SIZE = ${bestResult.chunkSize}`);
    if (bestResult.chunkSize !== 200) {
      const diff = results.find((r) => r.chunkSize === 200);
      if (diff) {
        const extraCalls = bestResult.apiCalls - diff.apiCalls;
        console.log(
          `   (${extraCalls} llamadas extra vs chunk=200, pero ${results.find((r) => r.chunkSize === 200)?.jsonErrors ?? 0} errores JSON menos)`,
        );
      }
    }
  } else {
    console.log('\n⚠️ Todos los tamaños mostraron errores JSON — revisar conexión o cuota.');
  }

  console.log('\n📌 Para cambiar en producción:');
  console.log('   Editar src/modules/scraping/nlp/gemini.analyzer.ts');
  console.log('   const CHUNK_SIZE = <valor>;');
  console.log('\n' + '='.repeat(70) + '\n');
}

main().catch((err) => {
  console.error('\n❌ Error fatal:', err);
  process.exit(1);
});

import fs from 'fs';
import path from 'path';
