  console.log('2️⃣  VERIFICAR: Las actividades originales se mantienen');
  console.log('═'.repeat(80) + '\n');

  const keptIds = EXPECTED_DUPLICATES.map(d => d.kept);
  const keptActivities = await p.activity.findMany({
    where: { id: { in: keptIds } },
    select: { id: true, title: true, startDate: true, provider: { select: { name: true } } },
  });

  if (keptActivities.length === EXPECTED_DUPLICATES.length) {
    console.log(`✅ Confirmado: ${EXPECTED_DUPLICATES.length} actividades originales se mantienen\n`);
    keptActivities.forEach(a => {
      console.log(`   ✓ "${a.title}" (${a.provider.name})`);
    });
    console.log('');
  } else {
    console.log(`❌ ERROR: Faltan ${EXPECTED_DUPLICATES.length - keptActivities.length} actividades\n`);
  }

  // 3. Análisis de similitud de los pares eliminados
  console.log('═'.repeat(80));
  console.log('3️⃣  ANÁLISIS: Similitud de pares eliminados');
  console.log('═'.repeat(80) + '\n');

  console.log('Verificando que los eliminados son realmente similares a los mantenidos:\n');

  for (const pair of EXPECTED_DUPLICATES) {
    const keptActivity = keptActivities.find(a => a.id === pair.kept);
    if (!keptActivity) continue;

    const keptTitle = keptActivity.title;
    const similarity = calculateSimilarity(keptTitle, pair.title);

    console.log(`  ${pair.title}`);
    console.log(`  ${'-'.repeat(70)}`);
    console.log(`  Mantenida: "${keptTitle}"`);
    console.log(`  Similitud: ${similarity}%`);
    console.log(`  Eliminadas: ${pair.deleted.length} copias`);
    console.log('');
  }

  // 4. Estadísticas finales
  console.log('═'.repeat(80));
  console.log('4️⃣  ESTADÍSTICAS');
  console.log('═'.repeat(80) + '\n');

  const totalNow = await p.activity.count();
  const uniqueTitles = await p.activity.findMany({
    select: { title: true },
    distinct: ['title'],
  });

  console.log(`Total de actividades: ${totalNow}`);
  console.log(`Títulos únicos (exactos): ${uniqueTitles.length}`);
  console.log(`Promedio de repetición: ${(totalNow / uniqueTitles.length).toFixed(2)}x\n`);

  // 5. Buscar si aún hay duplicados similares
  console.log('═'.repeat(80));
  console.log('5️⃣  BÚSQUEDA: Duplicados similares restantes (>90%)');
  console.log('═'.repeat(80) + '\n');

  const allActivities = await p.activity.findMany({
    select: { id: true, title: true },
  });

  let similarPairsFound = 0;

  for (let i = 0; i < allActivities.length; i++) {
    for (let j = i + 1; j < allActivities.length; j++) {
      const sim = calculateSimilarity(allActivities[i].title, allActivities[j].title);
      if (sim >= 90) {
        similarPairsFound++;
        console.log(`  ⚠️ ${sim}% similitud:`);
        console.log(`     A: "${allActivities[i].title}"`);
        console.log(`     B: "${allActivities[j].title}"\n`);
      }
    }
  }

  if (similarPairsFound === 0) {
    console.log('✅ No se encontraron duplicados similares (>90%)\n');
  } else {
    console.log(`⚠️ ${similarPairsFound} pares similares encontrados (revisar manualmente)\n`);
  }

  console.log('═'.repeat(80));
  console.log('✅ VALIDACIÓN COMPLETADA');
  console.log('═'.repeat(80) + '\n');

  await p.$disconnect();
}

validateCleanup().catch(console.error);

// =============================================================================
// EmptyState — Estado vacío context-aware para /actividades
// Muestra sugerencias específicas según qué filtros están activos
// =============================================================================

import Link from 'next/link';
import { getCategoryEmoji } from '@/lib/category-utils';
import ActivityCard from './ActivityCard';
import { ZeroResultsTracker } from '@/components/analytics/ZeroResultsTracker';

interface PopularCategory {
  id: string;
  name: string;
}

interface EmptyStateProps {
  search?: string;
  ageMin?: number;
  ageMax?: number;
  categoryId?: string;
  categoryName?: string;
  type?: string;
  audience?: string;
  popularCategories: PopularCategory[];
  fallbackActivities?: any[];
  favoriteIds?: Set<string>;
}

const TYPE_LABELS: Record<string, string> = {
  RECURRING: 'recurrentes',
  ONE_TIME: 'de única vez',
  CAMP: 'campamentos',
  WORKSHOP: 'talleres',
};

const AUDIENCE_LABELS: Record<string, string> = {
  KIDS: 'niños',
  FAMILY: 'familia',
  ADULTS: 'adultos',
};

export function EmptyState({
  search,
  ageMin,
  ageMax,
  categoryId,
  categoryName,
  type,
  audience,
  popularCategories,
  fallbackActivities = [],
  favoriteIds = new Set(),
}: EmptyStateProps) {
  const hasFilters = search || ageMin != null || ageMax != null || categoryId || type || audience;

  // Construir titular contextual
  let headline = 'Sin resultados para esa combinación de filtros';
  if (search) {
    headline = `No encontramos resultados para "${search}"`;
  } else if (categoryId && categoryName) {
    headline = `No hay actividades en "${categoryName}" con esos filtros`;
  }

  // Sugerencias específicas según filtros activos
  const tips: string[] = [];
  if (search) {
    tips.push('Revisa que no haya errores tipográficos');
    tips.push('Prueba con términos más generales, como "arte" o "música"');
  }
  if (ageMin != null || ageMax != null) {
    const rangeText = ageMin != null && ageMax != null
      ? `${ageMin}–${ageMax} años`
      : ageMin != null
      ? `desde ${ageMin} años`
      : `hasta ${ageMax} años`;
    tips.push(`Amplía el rango de edad (ahora filtrado por ${rangeText})`);
  }
  if (type) {
    tips.push(`Prueba sin filtrar por tipo "${TYPE_LABELS[type] ?? type}"`);
  }
  if (audience) {
    tips.push(`Prueba sin filtrar por audiencia "${AUDIENCE_LABELS[audience] ?? audience}"`);
  }
  if (tips.length === 0) {
    tips.push('Intenta con otros filtros o explora por categoría');
  }

  return (
    <div className="flex flex-col items-center py-20 gap-6 text-center">
      <ZeroResultsTracker 
        query={search} 
        filters={{ ageMin: ageMin?.toString() || '', ageMax: ageMax?.toString() || '', categoryId: categoryId || '', type: type || '', audience: audience || '' }}
      />
      {/* Ilustración */}
      <div className="flex flex-col items-center gap-2">
        <span className="text-6xl select-none">🔍</span>
        <h2 className="text-xl font-semibold text-[var(--hp-text-primary)] max-w-sm">{headline}</h2>
        <p className="text-sm text-[var(--hp-text-muted)] max-w-xs">
          {tips[0]}
        </p>
      </div>

      {/* Lista de sugerencias (cuando hay más de una) */}
      {tips.length > 1 && (
        <ul className="text-sm text-[var(--hp-text-secondary)] flex flex-col gap-1.5 text-left max-w-xs">
          {tips.map((tip, i) => (
            <li key={i} className="flex items-start gap-2">
              <span className="text-brand-400 mt-0.5">→</span>
              {tip}
            </li>
          ))}
        </ul>
      )}

      {/* CTA principal */}
      {hasFilters && (
        <Link
          href="/actividades"
          className="rounded-xl bg-brand-600 px-6 py-2.5 text-sm font-semibold text-white hover:bg-brand-700 transition-colors"
        >
          Limpiar filtros y ver todo
        </Link>
      )}

      {/* Categorías populares como sugerencias rápidas */}
      {popularCategories.length > 0 && (
        <div className="flex flex-col items-center gap-3 mt-2">
          <p className="text-xs font-semibold text-[var(--hp-text-muted)] tracking-wide">
            O explora estas categorías
          </p>
          <div className="flex flex-wrap justify-center gap-2 max-w-sm">
            {popularCategories.slice(0, 6).map((cat) => (
              <a
                key={cat.id}
                href={`/actividades?categoryId=${cat.id}`}
                className="flex items-center gap-1.5 rounded-full border border-[var(--hp-border)] bg-[var(--hp-bg-surface)] px-3 py-1.5 text-sm text-[var(--hp-text-primary)] hover:border-brand-300 hover:text-brand-700 transition-colors"
              >
                <span>{getCategoryEmoji(cat.name)}</span>
                {cat.name}
              </a>
            ))}
          </div>
        </div>
      )}

      {/* UX Fallback: Actividades de recomendación en caso nulo */}
      {fallbackActivities.length > 0 && (
        <div className="mt-12 text-left w-full border-t border-[var(--hp-border)] pt-10">
          <h3 className="text-xl font-bold text-[var(--hp-text-primary)] mb-6 tracking-tight">
            No encontramos resultados. Estas actividades podrían gustarte:
          </h3>
          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-4">
            {fallbackActivities.slice(0, 4).map((activity) => (
              <ActivityCard
                key={activity.id}
                activity={activity}
                isFavorited={favoriteIds.has(activity.id)}
              />
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

'use client';
// =============================================================================
// MapInner — componente Leaflet real (importado sin SSR desde MapView)
// Centro dinámico:
//   1. fitBounds sobre todos los pines (si existen)
//   2. city.defaultLat/Lng/Zoom del CityProvider (si ciudad seleccionada)
//   3. DEFAULT_CENTER como último recurso defensivo
// =============================================================================

import { useEffect, useRef, useState } from 'react';
import { activityPath } from '@/lib/activity-url';
import { useCity } from '@/components/providers/CityProvider';

export interface MapMarker {
  id:           string;
  title:        string;
  lat:          number;
  lng:          number;
  category:     string | null;
  locationName: string;
  priceLabel:   string;
}

interface Props {
  searchParams: string; // ?q=... para /api/activities/map
  height?: string;
}

// Último recurso defensivo (jambás debería usarse si CityProvider está montado)
const EMERGENCY_CENTER: [number, number] = [4.711, -74.0721];
const EMERGENCY_ZOOM = 11;

export default function MapInner({ searchParams, height = '520px' }: Props) {
  const containerRef  = useRef<HTMLDivElement>(null);
  const mapRef        = useRef<any>(null);        // instancia L.Map
  const layerGroupRef = useRef<any>(null);        // L.LayerGroup para los pines

  const { city } = useCity();

  const [markers,  setMarkers]  = useState<MapMarker[]>([]);
  const [loading,  setLoading]  = useState(true);
  const [error,    setError]    = useState<string | null>(null);

  // ── Fetch markers cuando cambian los filtros ─────────────────────────────
  // cityId ya llega garantizado en searchParams desde MapView (via CityProvider).
  // Si no hay cityId aún (CityProvider montando), esperar en lugar de disparar HTTP 400.
  useEffect(() => {
    if (!searchParams.includes('cityId=')) return;

    setLoading(true);
    setError(null);

    const controller = new AbortController();

    fetch(`/api/activities/map?${searchParams}`, { signal: controller.signal })
      .then((r) => {
        if (!r.ok) throw new Error(`HTTP ${r.status}`);
        return r.json();
      })
      .then((data) => {
        setMarkers(data.markers ?? []);
        setLoading(false);
      })
      .catch((err: unknown) => {
        if (err instanceof Error && err.name === 'AbortError') return;
        setError('No se pudo cargar el mapa');
        setLoading(false);
      });

    return () => controller.abort();
  }, [searchParams]);

  // ── Inicializar mapa Leaflet (una sola vez) ───────────────────────────────
  useEffect(() => {
    if (!containerRef.current || mapRef.current) return;

    import('leaflet').then((L) => {
      // Fix CSS con import dinámico
      const link = document.createElement('link');
      link.rel  = 'stylesheet';
      link.href = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.css';
      document.head.appendChild(link);

      const map = L.map(containerRef.current!, {
        // Centro inicial neutro: será sobreescrito por fitBounds o city.defaultCenter
        center: city
          ? [city.defaultLat, city.defaultLng] as [number, number]
          : EMERGENCY_CENTER,
        zoom: city ? city.defaultZoom : EMERGENCY_ZOOM,
        zoomControl: true,
      });

      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '© <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>',
        maxZoom: 19,
      }).addTo(map);

      layerGroupRef.current = L.layerGroup().addTo(map);
      mapRef.current = map;
    });

    return () => {
      mapRef.current?.remove();
      mapRef.current        = null;
      layerGroupRef.current = null;
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps -- 'city' se usa solo para el centro inicial; re-inicializar el mapa al cambiar ciudad destruiría la instancia Leaflet
  }, []);

  // ── Actualizar pines cuando cambian los datos ─────────────────────────────
  useEffect(() => {
    if (!mapRef.current || !layerGroupRef.current) return;

    import('leaflet').then((L) => {
      const lg = layerGroupRef.current;
      if (!lg) return;
      lg.clearLayers();

      if (markers.length === 0) return;

      // Icono personalizado: pin índigo con rotación clásica
      const makeIcon = () => L.divIcon({
        html: `<div style="
          width:26px;height:26px;
          background:#4f46e5;
          border:3px solid #fff;
          border-radius:50% 50% 50% 0;
          transform:rotate(-45deg);
          box-shadow:0 2px 8px rgba(0,0,0,.35);
          cursor:pointer;
        "></div>`,
        className: '',
        iconSize:    [26, 26],
        iconAnchor:  [13, 26],
        popupAnchor: [0, -28],
      });

      markers.forEach((m) => {
        const href = activityPath(m.id, m.title);
        const popup = /* html */`
          <div style="min-width:200px;font-family:system-ui,sans-serif;line-height:1.4">
            <p style="font-weight:700;font-size:13px;margin:0 0 5px;color:#111">${escHtml(m.title)}</p>
            ${m.category ? `<span style="
              display:inline-block;background:#ede9fe;color:#5b21b6;
              border-radius:20px;padding:1px 8px;font-size:11px;margin-bottom:6px
            ">${escHtml(m.category)}</span>` : ''}
            <div style="display:flex;justify-content:space-between;align-items:center;font-size:11px;color:#555;margin-bottom:8px">
              <span>📍 ${escHtml(m.locationName)}</span>
              ${m.priceLabel ? `<span style="font-weight:600;color:${m.priceLabel === 'Gratis' ? '#059669' : '#374151'}">${escHtml(m.priceLabel)}</span>` : ''}
            </div>
            <a href="${href}" style="
              display:block;background:#4f46e5;color:#fff;
              text-align:center;border-radius:8px;padding:6px 12px;
              font-size:12px;font-weight:600;text-decoration:none
            ">Ver actividad →</a>
          </div>
        `;

        L.marker([m.lat, m.lng], { icon: makeIcon() })
          .addTo(lg)
          .bindPopup(popup, { maxWidth: 260 });
      });

      // Ajustar vista para mostrar todos los pines
      if (markers.length === 1) {
        mapRef.current.setView([markers[0].lat, markers[0].lng], 14);
      } else if (markers.length > 1) {
        const bounds = L.latLngBounds(markers.map((m) => [m.lat, m.lng] as [number, number]));
        mapRef.current.fitBounds(bounds, { padding: [48, 48], maxZoom: 15 });
      } else if (city) {
        // Sin pines pero con ciudad seleccionada: centrar en coordenadas de la ciudad
        mapRef.current.setView([city.defaultLat, city.defaultLng], city.defaultZoom);
      }
      // Sin pines ni ciudad: el map quedó en el centro inicial (EMERGENCY_CENTER)
    });
  }, [markers, city]);

  const isEmpty = !loading && !error && markers.length === 0;

  return (
    <div
      className='relative rounded-2xl overflow-hidden border border-[var(--hp-border)] shadow-[var(--hp-shadow-md)]'
      style={{ height }}
    >
      {/* Overlay: loading */}
      {loading && (
        <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-[var(--hp-bg-page)] gap-2">
          <div className="h-8 w-8 animate-spin rounded-full border-4 border-[var(--hp-border-subtle)] border-t-[var(--hp-primary)]" />
          <p className="text-sm text-[var(--hp-text-secondary)]">Cargando mapa...</p>
        </div>
      )}
      {/* Overlay: error */}
      {error && (
        <div className="absolute inset-0 z-20 flex items-center justify-center bg-[var(--hp-bg-page)]">
          <p className="text-sm text-error-500">{error}</p>
        </div>
      )}
      {/* Overlay: sin resultados */}
      {isEmpty && (
        <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-[var(--hp-bg-page)] gap-2">
          <span className="text-4xl">🗺</span>
          <p className="text-sm text-[var(--hp-text-secondary)]">No hay actividades con ubicación para estos filtros</p>
        </div>
      )}
      {/* Contador flotante */}
      {!loading && !error && markers.length > 0 && (
        <div className='absolute bottom-4 left-4 z-20 rounded-full bg-[var(--hp-bg-surface)]/90 px-3 py-1.5 text-xs font-semibold text-[var(--hp-text-primary)] shadow-[var(--hp-shadow-md)] backdrop-blur-sm'>
          {markers.length} {markers.length === 1 ? 'actividad' : 'actividades'} en el mapa
        </div>
      )}
      {/* Contenedor del mapa */}
      <div ref={containerRef} className="h-full w-full" />
    </div>
  );
}

/** Escapa HTML básico para el contenido del popup */
function escHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

