'use client';
// =============================================================================
// ActivityDetailMapInner — implementación Leaflet real del mini-mapa
// Cargado sólo en cliente (ssr: false desde ActivityDetailMap)
// =============================================================================

import { useEffect, useRef } from 'react';

interface Props {
  lat:          number;
  lng:          number;
  locationName: string;
  address?:     string | null;
}

export default function ActivityDetailMapInner({ lat, lng, locationName, address }: Props) {
  const containerRef = useRef<HTMLDivElement>(null);
  const mapRef       = useRef<any>(null);

  useEffect(() => {
    if (!containerRef.current || mapRef.current) return;

    // CSS de Leaflet dinámico (evita conflicto webpack/SSR)
    if (!document.getElementById('leaflet-css')) {
      const link  = document.createElement('link');
      link.id   = 'leaflet-css';
      link.rel  = 'stylesheet';
      link.href = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.css';
      document.head.appendChild(link);
    }

    import('leaflet').then((L) => {
      if (mapRef.current) return; // guard doble-montaje

      const map = L.map(containerRef.current!, {
        center:           [lat, lng],
        zoom:             15,
        zoomControl:      true,
        scrollWheelZoom:  false,   // no secuestra el scroll de la página
        attributionControl: false, // minimiza UI para el mini-mapa
      });

      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        maxZoom: 19,
      }).addTo(map);

      // Pin índigo igual al del mapa de lista
      const icon = L.divIcon({
        html: `<div style="
          width:26px;height:26px;
          background:#4f46e5;
          border:3px solid #fff;
          border-radius:50% 50% 50% 0;
          transform:rotate(-45deg);
          box-shadow:0 2px 8px rgba(0,0,0,.35);
        "></div>`,
        className:   '',
        iconSize:    [26, 26],
        iconAnchor:  [13, 26],
        popupAnchor: [0, -28],
      });

      const popup = `
        <div style="font-family:system-ui,sans-serif;font-size:13px;min-width:160px">
          <p style="font-weight:700;margin:0 0 3px;color:#111">${escHtml(locationName)}</p>
          ${address ? `<p style="margin:0;color:#555;font-size:12px">${escHtml(address)}</p>` : ''}
        </div>
      `;

      L.marker([lat, lng], { icon })
        .addTo(map)
        .bindPopup(popup, { maxWidth: 220 })
        .openPopup();

      mapRef.current = map;
    });

    return () => {
      mapRef.current?.remove();
      mapRef.current = null;
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // sólo al montar — lat/lng no cambian en detalle

  return (
    <div
      ref={containerRef}
      className="w-full rounded-xl overflow-hidden border border-[var(--hp-border)]"
      style={{ height: '180px' }}
    />
  );
}

function escHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

'use client'

// =============================================================================
// ActivityMap — Mapa Leaflet de actividades (client-only, ssr: false)
// Centro dinámico: fitBounds sobre pines reales.
// Si no hay pines (ciudad sin actividades geocodificadas), usa city.defaultCenter.
// =============================================================================

// eslint-disable-next-line no-restricted-imports -- leaflet requiere su CSS propio, no hay alternativa vía módulos CSS
import 'leaflet/dist/leaflet.css'
import { useEffect, useRef } from 'react'
import { activityPath } from '@/lib/activity-url'

export interface MapPoint {
  id: string
  title: string
  imageUrl: string | null
  priceLabel: string | null
  category: string | null
  provider: string | null
  lat: number
  lng: number
}

interface Props {
  points: MapPoint[]
  /** Coordenadas por defecto de la ciudad seleccionada (de City.defaultLat/Lng/Zoom) */
  defaultCenter?: { lat: number; lng: number; zoom: number }
}

// Colores por categoría (primer char del nombre → hash simple)
function markerColor(category: string | null): string {
  const colors = ['#f97316', '#8b5cf6', '#0ea5e9', '#10b981', '#f43f5e', '#eab308']
  if (!category) return colors[0]
  return colors[category.charCodeAt(0) % colors.length]
}

export default function ActivityMap({ points, defaultCenter }: Props) {
  const containerRef = useRef<HTMLDivElement>(null)
  const mapRef = useRef<any>(null)

  useEffect(() => {
    if (!containerRef.current || mapRef.current) return

    import('leaflet').then((L) => {
      if (!containerRef.current || mapRef.current) return

      // Fix default icon paths (webpack/Next.js issue con Leaflet)
      // @ts-expect-error — _getIconUrl no está en el tipo público de Leaflet pero existe en runtime
      delete L.Icon.Default.prototype._getIconUrl
      L.Icon.Default.mergeOptions({
        iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
        iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
        shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
      })

      // Centro inicial neutro — será sobreescrito por fitBounds o defaultCenter
      const map = L.map(containerRef.current).setView([4.7110, -74.0721], 12)
      mapRef.current = map

      // Tiles OpenStreetMap (sin API key)
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '© <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>',
        maxZoom: 18,
      }).addTo(map)

      // Pins de actividades
      const markers: any[] = []
      points.forEach((point) => {
        const color = markerColor(point.category)

        const icon = L.divIcon({
          className: '',
          html: `<div style="width:12px;height:12px;border-radius:50%;background:${color};border:2px solid white;box-shadow:0 1px 3px rgba(0,0,0,.4)"></div>`,
          iconSize: [12, 12],
          iconAnchor: [6, 6],
        })

        const path = activityPath(point.id, point.title)
        const imgTag = point.imageUrl
          ? `<img src="${point.imageUrl}" alt="" style="width:100%;height:72px;object-fit:cover;border-radius:6px;margin-bottom:6px"/>`
          : ''
        const price = point.priceLabel
          ? `<span style="font-size:11px;background:${point.priceLabel === 'Gratis' ? '#d1fae5' : '#fed7aa'};color:${point.priceLabel === 'Gratis' ? '#065f46' : '#7c2d12'};padding:1px 6px;border-radius:999px">${point.priceLabel}</span>`
          : ''

        const popup = `
          <div style="width:180px;font-family:system-ui,sans-serif">
            ${imgTag}
            <p style="margin:0 0 4px;font-weight:600;font-size:13px;line-height:1.3">${point.title}</p>
            ${point.category ? `<p style="margin:0 0 4px;font-size:11px;color:#6b7280">${point.category}</p>` : ''}
            ${price}
            <a href="${path}" style="display:block;margin-top:8px;text-align:center;background:#f97316;color:white;padding:4px 0;border-radius:6px;font-size:12px;font-weight:600;text-decoration:none">Ver actividad →</a>
          </div>`

        const marker = L.marker([point.lat, point.lng], { icon })
          .addTo(map)
          .bindPopup(popup, { maxWidth: 200 })
        markers.push(marker)
      })

      // ── Centro dinámico ───────────────────────────────────────────────────
      // fitBounds si hay pines reales (evita fitBounds([]) que rompe Leaflet)
      if (markers.length > 0) {
        const group = L.featureGroup(markers)
        map.fitBounds(group.getBounds(), { padding: [40, 40], maxZoom: 15 })
      } else if (defaultCenter) {
        // Ciudad sin pines geocodificados → coordenadas base de la ciudad en DB
        map.setView([defaultCenter.lat, defaultCenter.lng], defaultCenter.zoom)
      }
      // Sin pines ni defaultCenter → el setView inicial queda como último recurso
    })

    return () => {
      if (mapRef.current) {
        mapRef.current.remove()
        mapRef.current = null
      }
    }
  }, [points, defaultCenter])

  return (
    <div
      ref={containerRef}
      style={{ height: '580px', width: '100%' }}
      className="rounded-2xl overflow-hidden"
    />
  )
}

"use client";

import { useEffect, useRef } from "react";
import { batchTracker } from "@/lib/track";

interface FeedImpressionTrackerProps {
  activityId: string;
  context?: Record<string, any>;
  children: React.ReactNode;
}

/**
 * Discovery Observability Layer
 * Mide qué actividades entran en el viewport (50% visibles por > 1s).
 * Usa un BatchTracker interno para evitar sobrecarga (batching + deduplicación por sesión).
 */
export function FeedImpressionTracker({ activityId, context, children }: FeedImpressionTrackerProps) {
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;

    let timer: NodeJS.Timeout;

    const observer = new IntersectionObserver(
      (entries) => {
        const [entry] = entries;
        if (entry.isIntersecting) {
          // Iniciar conteo de 1 segundo
          timer = setTimeout(() => {
            batchTracker.trackFeedImpression(activityId, context);
          }, 1000);
        } else {
          // Si sale del viewport antes de 1s, cancelar
          if (timer) clearTimeout(timer);
        }
      },
      {
        threshold: 0.5, // 50% visible
      }
    );

    observer.observe(el);

    return () => {
      observer.unobserve(el);
      if (timer) clearTimeout(timer);
    };
  }, [activityId, context]);

  return (
    <div ref={ref} className="h-full w-full">
      {children}
    </div>
  );
}

import React from 'react';
import Link from 'next/link';

export interface SmartLinkProps extends React.AnchorHTMLAttributes<HTMLAnchorElement> {
  href: string;
}

/**
 * SmartLink: Componente de navegación resiliente
 * 
 * Intercepta los enlaces para evitar el bug de "doble hash" en Next.js (App Router).
 * - Si el enlace es una ruta normal (ej. "/actividades"), usa el <Link> de Next.js para SPA (sin recarga).
 * - Si el enlace es un ancla (ej. "/#categorias"), usa un tag <a> nativo, forzando al navegador a manejar el hash sin interferencias de Next.js.
 */
export function SmartLink({ href, children, ...props }: SmartLinkProps) {
  // Verificamos si es un hash link (ej. "#seccion", "/#seccion")
  const isHashLink = href.startsWith('/#') || href.startsWith('#');

  if (isHashLink) {
    return (
      <a href={href} {...props}>
        {children}
      </a>
    );
  }

  // Next.js Link tipado
  return (
    <Link href={href} {...(props as any)}>
      {children}
    </Link>
  );
}

import { describe, it, expect, vi, beforeEach } from 'vitest'

// Storage mock - must be defined before module import
let store: Record<string, string> = {}

const localStorageMock = {
  getItem: vi.fn((key: string) => store[key] ?? null),
  setItem: vi.fn((key: string, value: string) => { store[key] = value }),
  removeItem: vi.fn((key: string) => { delete store[key] }),
  clear: vi.fn(() => { store = {} }),
  get length() { return Object.keys(store).length },
  key: vi.fn(() => null),
}

// Define both window and localStorage on globalThis before importing module
Object.defineProperty(globalThis, 'window', { value: globalThis, writable: true, configurable: true })
Object.defineProperty(globalThis, 'localStorage', { value: localStorageMock, writable: true, configurable: true })

// Now import the module (it will see window + localStorage)
import { addToHistory, clearHistory } from '../useActivityHistory'

const STORAGE_KEY = 'habitaplan:activity-history'

function getStoredHistory() {
  const raw = store[STORAGE_KEY]
  return raw ? JSON.parse(raw) : []
}

describe('useActivityHistory', () => {
  beforeEach(() => {
    store = {}
    vi.clearAllMocks()
  })

  it('almacena entrada en localStorage', () => {
    addToHistory({ activityId: 'a1', title: 'Taller de arte', imageUrl: null })

    const stored = getStoredHistory()
    expect(stored).toHaveLength(1)
    expect(stored[0].activityId).toBe('a1')
    expect(stored[0].title).toBe('Taller de arte')
    expect(stored[0].imageUrl).toBeNull()
  })

  it('deduplica por activityId (mueve al frente)', () => {
    addToHistory({ activityId: 'a1', title: 'First', imageUrl: null })
    addToHistory({ activityId: 'a2', title: 'Second', imageUrl: null })
    addToHistory({ activityId: 'a1', title: 'First updated', imageUrl: '/img.jpg' })

    const stored = getStoredHistory()
    expect(stored).toHaveLength(2)
    expect(stored[0].activityId).toBe('a1')
    expect(stored[0].title).toBe('First updated')
    expect(stored[1].activityId).toBe('a2')
  })

  it('limita a 50 items con FIFO', () => {
    for (let i = 0; i < 55; i++) {
      addToHistory({ activityId: `a${i}`, title: `Activity ${i}`, imageUrl: null })
    }

    const stored = getStoredHistory()
    expect(stored).toHaveLength(50)
    expect(stored[0].activityId).toBe('a54')
    expect(stored[49].activityId).toBe('a5')
  })

  it('agrega viewedAt timestamp', () => {
    const before = Date.now()
    addToHistory({ activityId: 'a1', title: 'Test', imageUrl: null })

    const stored = getStoredHistory()
    expect(stored[0].viewedAt).toBeDefined()
    const viewedTime = new Date(stored[0].viewedAt).getTime()
    expect(viewedTime).toBeGreaterThanOrEqual(before)
  })

  it('clearHistory elimina todas las entradas', () => {
    addToHistory({ activityId: 'a1', title: 'Test', imageUrl: null })
    clearHistory()

    const stored = getStoredHistory()
    expect(stored).toHaveLength(0)
  })

  it('ordena mas reciente primero', () => {
    addToHistory({ activityId: 'a1', title: 'First', imageUrl: null })
    addToHistory({ activityId: 'a2', title: 'Second', imageUrl: null })
    addToHistory({ activityId: 'a3', title: 'Third', imageUrl: null })

    const stored = getStoredHistory()
    expect(stored[0].activityId).toBe('a3')
    expect(stored[1].activityId).toBe('a2')
    expect(stored[2].activityId).toBe('a1')
  })

  it('retorna array vacio cuando localStorage esta vacio', () => {
    const stored = getStoredHistory()
    expect(stored).toHaveLength(0)
  })

  it('maneja errores de localStorage sin lanzar excepcion', () => {
    localStorageMock.setItem.mockImplementationOnce(() => {
      throw new Error('QuotaExceededError')
    })

    expect(() => {
      addToHistory({ activityId: 'a1', title: 'Test', imageUrl: null })
    }).not.toThrow()
  })

  it('actualiza viewedAt al re-ver misma actividad', () => {
    addToHistory({ activityId: 'a1', title: 'Test', imageUrl: null })
    const first = getStoredHistory()[0].viewedAt

    // Small delay to get different timestamp
    addToHistory({ activityId: 'a2', title: 'Other', imageUrl: null })
    addToHistory({ activityId: 'a1', title: 'Test', imageUrl: null })

    const stored = getStoredHistory()
    expect(stored[0].activityId).toBe('a1')
    expect(stored[0].viewedAt).toBeDefined()
    // Should still be first (most recent)
    expect(stored).toHaveLength(2)
  })

  it('no duplica entradas', () => {
    addToHistory({ activityId: 'a1', title: 'Test', imageUrl: null })
    addToHistory({ activityId: 'a1', title: 'Test', imageUrl: null })
    addToHistory({ activityId: 'a1', title: 'Test', imageUrl: null })

    const stored = getStoredHistory()
    expect(stored).toHaveLength(1)
  })
})

