/**
 * scheduler.core.ts — v2
 *
 * Cambio principal respecto a v1:
 *   v1: reparseCount > 0 → PARSE_ONLY → discovery DESACTIVADO
 *       Consecuencia: fuentes con deuda de reparse nunca descubrían contenido nuevo
 *       (detectado con audit-coverage.ts el 2026-04-30: Idartes perdía 11 URLs nuevas,
 *        Sec. Cultura perdía 15).
 *
 *   v2: PARSE_ONLY ya no se auto-asigna por deuda de reparse.
 *       Discovery SIEMPRE ocurre. El reparse se ejecuta como una fase adicional
 *       al final del run, controlado por el campo `reparseCount` en SchedulePlan.
 *       Budget = discovery_cost + reparse_cost (combinado, capped a 20 URLs de reparse).
 *
 * Archivos de referencia:
 *   Backup v1: scheduler.core.v1.ts / scheduler.types.v1.ts
 */
import { Mode, SourceStats, SchedulePlan } from './scheduler.types';
import { createLogger } from '../../../lib/logger';

const log = createLogger('scraping:scheduler');

export const DEPTH: Record<Mode, { maxUrls: number }> = {
  DEEP:       { maxUrls: 40 },
  SURFACE:    { maxUrls: 15 },
  PING:       { maxUrls: 5  },
  PARSE_ONLY: { maxUrls: Infinity }, // Reservado para uso manual / backward-compat
};

/** Máximo de URLs de reparse a procesar por fuente por run (evita que reparse devore budget) */
const MAX_REPARSE_PER_RUN = 20;

/**
 * v2: Selecciona el modo de DISCOVERY para una fuente.
 *
 * PARSE_ONLY ya NO se retorna automáticamente cuando hay reparseCount.
 * El reparse ocurre como fase adicional independientemente del modo de discovery.
 */
export function pickMode(s: SourceStats): Mode {
  // Penalización a fuentes devoradoras de cuota sin retorno
  if (s.avgCost > 80 && s.saveRate < 0.1) return 'SURFACE';

  // Boost de eficiencia a fuentes orgánicamente limpias
  if (s.saveRate > 0.3 && s.avgCost < 30) return 'DEEP';

  // Conversión pura probada por usuarios
  if (s.ctr7d >= 0.20 && s.health >= 0.7) return 'DEEP';

  // Fuentes problemáticas → PING (solo exploración mínima)
  if (s.health < 0.4 || s.saveRate < 0.05) return 'PING';

  return 'SURFACE';
}

/**
 * Estima el costo combinado (discovery + reparse) para presupuesto de Gemini.
 *
 * Discovery: maxUrls * 1.5 (1 llamada discovery + 0.5 preflight por URL)
 * Reparse:   min(reparseCount, MAX_REPARSE_PER_RUN) * 1 (1 llamada por URL)
 */
export function estimateCost(maxUrls: number, mode: Mode, reparseCount: number = 0): number {
  if (mode === 'PARSE_ONLY') {
    // Backward-compat: PARSE_ONLY puro (sin discovery) solo cuenta reparse
    return Math.min(reparseCount, MAX_REPARSE_PER_RUN) * 1;
  }
  const discoveryCost = maxUrls * 1.5;
  const reparseCost   = Math.min(reparseCount, MAX_REPARSE_PER_RUN) * 1;
  return discoveryCost + reparseCost;
}

export interface PlanResult {
  planned: SchedulePlan[];
  skipped: { source: any; mode: Mode; reason: string }[];
  budgetUsed: number;
}

/**
 * v2: Resuelve la estrategia de extracción para una lista de fuentes.
 *
 * Orden de prioridad (dicta en qué se gasta primero el presupuesto):
 *   1. DEEP   — fuentes de alto rendimiento probado
 *   2. SURFACE — mantenimiento estándar
 *   3. PING   — exploración mínima / fuentes problemáticas
 *
 * El reparse ya no tiene prioridad propia: va montado sobre el modo de discovery
 * como costo adicional. Si no hay budget para el reparse, se hace discovery solo.
 */
export function buildPredictivePlan(
  sources: { source: any; stats: SourceStats }[],
  totalBudget: number
): PlanResult {
  const plan: SchedulePlan[] = [];
  const skipped: PlanResult['skipped'] = [];

  let budgetRemaining = totalBudget;
  const maxBudgetPerSource = 0.25 * totalBudget;

  // Prioridad de discovery: DEEP primero (mayor valor), luego SURFACE, luego PING
  const modePriority: Record<Mode, number> = { DEEP: 1, SURFACE: 2, PING: 3, PARSE_ONLY: 4 };

  const ordered = [...sources].sort((a, b) => {
    const aMode = pickMode(a.stats);
    const bMode = pickMode(b.stats);
    return modePriority[aMode] - modePriority[bMode];
  });

  for (const item of ordered) {
    const { source, stats } = item;
    const mode    = pickMode(stats);
    const maxUrls = DEPTH[mode].maxUrls;

    // Calcular reparse capped para esta fuente
    const reparseCount = Math.min(stats.reparseCount, MAX_REPARSE_PER_RUN);

    // Costo combinado discovery + reparse
    const fullCost = estimateCost(maxUrls, mode, stats.reparseCount);

    if (fullCost > budgetRemaining) {
      // Intentar sin reparse si discovery solo cabe
      const discoverOnlyCost = maxUrls * 1.5;
      if (discoverOnlyCost <= budgetRemaining) {
        // Discovery sin reparse: preferible a saltarse la fuente
        plan.push({ source, mode, maxUrls, estimatedCost: discoverOnlyCost, reparseCount: 0 });
        budgetRemaining -= discoverOnlyCost;
        log.info(`[PLAN] ${source.name}: reparse omitido por budget (discovery_only=${discoverOnlyCost})`);
      } else {
        skipped.push({ source, mode, reason: `Excede budget (req: ${fullCost}, rem: ${budgetRemaining})` });
      }
      continue;
    }

    if (fullCost > maxBudgetPerSource) {
      skipped.push({ source, mode, reason: `Excede maxBudgetPerSource 25% (req: ${fullCost})` });
      continue;
    }

    plan.push({ source, mode, maxUrls, estimatedCost: fullCost, reparseCount });
    budgetRemaining -= fullCost;
  }

  log.info(
    `Plan generado: ${plan.length} fuentes, ` +
    `Presupuesto consumido estimado: ${totalBudget - budgetRemaining} / ${totalBudget}`
  );

  return {
    planned: plan,
    skipped,
    budgetUsed: totalBudget - budgetRemaining,
  };
}

import { Mode, SourceStats, SchedulePlan } from './scheduler.types';
import { createLogger } from '../../../lib/logger';

const log = createLogger('scraping:scheduler');

export const DEPTH: Record<Mode, { maxUrls: number }> = {
  DEEP: { maxUrls: 40 },
  SURFACE: { maxUrls: 15 },
  PING: { maxUrls: 5 },
  PARSE_ONLY: { maxUrls: Infinity },
};

/**
 * Selecciona el modo de extracción para una fuente basada en histórico.
 */
export function pickMode(s: SourceStats): Mode {
  if (s.reparseCount > 0) return 'PARSE_ONLY';

  // Penalización a fuentes devoradoras de cuota sin retorno
  if (s.avgCost > 80 && s.saveRate < 0.1) {
    return 'SURFACE';
  }

  // Boost de eficiencia a fuentes orgánicamente limpias
  if (s.saveRate > 0.3 && s.avgCost < 30) {
    return 'DEEP';
  }

  // Conversión pura probada por usuarios
  if (s.ctr7d >= 0.20 && s.health >= 0.7) return 'DEEP';

  // Fuentes problemáticas mitigadas a PING.
  // NOTA isGov eliminado de esta condición: muchas de nuestras mejores fuentes son
  // gubernamentales (BibloRed, Idartes, Banrep). Antes `|| s.isGov` las mandaba a
  // PING independientemente de su rendimiento. Ahora solo penaliza health o saveRate.
  if (s.health < 0.4 || s.saveRate < 0.05) return 'PING';

  return 'SURFACE';
}

/**
 * Estima el costo (calls / Gemini) según el modo y límite.
 */
export function estimateCost(maxUrls: number, mode: Mode, reparseCount: number = 0): number {
  if (mode === 'PARSE_ONLY') {
    // 1 token por reparse (pipeline sin discovery)
    return reparseCount * 1;
  }
  
  // Para operaciones con discovery, estimamos 1 llamada para discovery y 0.5 llamada para filter pre-flight parse
  return maxUrls * 1.5;
}

export interface PlanResult {
  planned: SchedulePlan[];
  skipped: { source: any; mode: Mode; reason: string }[];
  budgetUsed: number;
  budgetWasted?: number;
}

/**
 * Resuelve la estrategia de extracción dada una lista de fuentes y el presupuesto diario de Gemini disponibles.
 */
export function buildPredictivePlan(
  sources: { source: any; stats: SourceStats }[],
  totalBudget: number
): PlanResult {
  const plan: SchedulePlan[] = [];
  const skipped: PlanResult['skipped'] = [];

  let budgetRemaining = totalBudget;
  const maxBudgetPerSource = 0.25 * totalBudget;
  const maxReparseBudget = 0.3 * totalBudget;
  let reparseBudgetUsed = 0;

  // Optimización de orden: la prioridad dicta en qué se gasta primero el presupuesto de Gemini (importante si la cuota es escasa).
  // 1. PARSE_ONLY (Recuperar la deuda que bajó el score del source)
  // 2. DEEP (Conversión real, nos pagan indirectamente por esto)
  // 3. SURFACE (Mantener fresco lo normal)
  // 4. PING (Ver si volvieron los zombies)
  const modePriority = { PARSE_ONLY: 1, DEEP: 2, SURFACE: 3, PING: 4 };

  // Copia modificable para iterar segura, asumiendo sources con estadísticas listadas.
  const ordered = [...sources].sort((a, b) => {
    const aMode = pickMode(a.stats);
    const bMode = pickMode(b.stats);
    return modePriority[aMode] - modePriority[bMode];
  });

  for (const item of ordered) {
    const { source, stats } = item;
    const mode = pickMode(stats);
    let maxUrls = DEPTH[mode].maxUrls;
    
    if (mode === 'PARSE_ONLY') {
      maxUrls = stats.reparseCount;
    }
    
    const cost = estimateCost(maxUrls, mode, stats.reparseCount);

    if (cost > budgetRemaining) {
      skipped.push({ source, mode, reason: `Excede budget local (req: ${cost}, rem: ${budgetRemaining})` });
      continue;
    }

    if (cost > maxBudgetPerSource && mode !== 'PARSE_ONLY') {
      // Degradar modo si excede su capa máxima y no es una recuperación nativa de parse
      // (ej. un DEEP muy ambicioso en fuente carísima).
      skipped.push({ source, mode, reason: `Excede maxBudgetPerSource 25% (req: ${cost})` });
      continue; 
    }

    if (mode === 'PARSE_ONLY') {
       if ((reparseBudgetUsed + cost) > maxReparseBudget) {
         skipped.push({ source, mode, reason: `Excede bucket maxReparseBudget 30%` });
         continue;
       }
       reparseBudgetUsed += cost;
    }

    plan.push({
      source,
      mode,
      maxUrls,
      estimatedCost: cost
    });
    budgetRemaining -= cost;
  }

  log.info(`Plan generado: ${plan.length} fuentes, Presupuesto consumido estimado: ${totalBudget - budgetRemaining} / ${totalBudget}`);

  return {
    planned: plan,
    skipped,
    budgetUsed: totalBudget - budgetRemaining
  };
}

export type Mode = 'DEEP' | 'SURFACE' | 'PING' | 'PARSE_ONLY';

export interface SourceStats {
  /** Source URL hostname (sin www) o alias de BD */
  sourceId: string;
  /** CTR real calculado (clicks / views) en los últimos 7 días */
  ctr7d: number;
  /** Promedio histórico de actividades guardadas / URLs descubiertas en % */
  saveRate: number;
  /** Health score actual de la base de datos (0-1) */
  health: number;
  /** Promedio de llamadas consumidas (Gemini tokens/costs) en las últimas 5 corridas */
  avgCost: number;
  /** Cantidad de URLs de la fuente en cache marcadas con needsReparse */
  reparseCount: number;
  /** Indica si la URL pertenece a dependencias gubernamentales (isGov = true) */
  isGov: boolean;
}

export interface SchedulePlan {
  /** Fuente objetivo que entrará al pipeline */
  source: any; // Se reemplazará con el modelo Source en ingest-sources.ts
  /** Modo predictivo seleccionado por la heurística */
  mode: Mode;
  /** Cantidad estimada de URLs a descubrir (si aplica) */
  maxUrls: number;
  /** Profundidad estimada en costos de LLM */
  estimatedCost: number;
}

import { getErrorMessage } from '../../lib/error';
import 'dotenv/config';
import { PrismaPg } from '@prisma/adapter-pg';
import { Prisma, PrismaClient, ActivityStatus } from '../../generated/prisma/client';
import { ActivityNLPResult, BatchPipelineResult } from './types';
import { calculateSimilarity, normalizeString } from './deduplication';
import { geocodeAddress } from '../../lib/geocoding';
import { createLogger } from '../../lib/logger';
import { ambiguityScore } from './ambiguity';
import { getAdaptiveRules, getSourceRules } from './adaptive-rules';
import { runDataPipeline } from './data-pipeline';
import { matchCity } from '../../modules/geo/city-matcher';
import { queueCityReview } from '../../modules/geo/city-review';
import { validateForPublish } from './quality/publish-validator';

const log = createLogger('scraping:storage');

// Prisma client propio para scripts standalone (no usa el singleton de Next.js)
const adapter = new PrismaPg({ connectionString: process.env.DATABASE_URL! });
const prisma = new PrismaClient({ adapter });

type SaveAction = 'CREATED_ACTIVE' | 'CREATED_PAUSED' | 'UPDATED_ACTIVE' | 'UPDATED_PAUSED' | 'DEDUPE_SKIPPED' | 'DISCARDED_QUALITY' | 'ERROR';

type SaveActivityResult = {
  id: string | null;
  action: SaveAction;
};

type SaveResult = {
  saved: number;
  created: number;
  updated: number;
  quarantined: number;
  active: number;
  skipped: number;
  dedupe_skipped: number;
  discarded: number;
  errors: string[];
};

type AdaptiveContext = {
  globalMetrics: { pctShort: number; pctNoise: number } | null;
  sourceHealthMap: Record<string, number>;
};

const EMPTY_ADAPTIVE_CTX: AdaptiveContext = { globalMetrics: null, sourceHealthMap: {} };

// Dominios que nunca deben almacenarse como fuente válida
const BLOCKED_DOMAINS = new Set([
  'agenciadigitalamd.com',
  'api.whatsapp.com', 'whatsapp.com',
  'telegram.me', 't.me',
  'linkedin.com', 'twitter.com', 'x.com', 'tiktok.com', 'facebook.com',
  'youtube.com', 'youtu.be', 'vimeo.com',
  'mercadolibre.com', 'amazon.com', 'rappi.com',
]);

// Mapa duro de dominios/cuentas a ciudades (bypass NLP)
// Fuentes abiertas (ej. FCE, BanRep con sedes múltiples) se omiten intencionalmente.
const HARDCODED_CITY_RULES: Array<{ match: (url: string, igUsername?: string) => boolean, city: string }> = [
  // --- Bogotá Oficial / Institucional ---
  { match: (url, _) => url.includes('bogota.gov.co'), city: 'Bogotá' },
  { match: (url, _) => url.includes('idartes.gov.co'), city: 'Bogotá' },
  { match: (url, _) => url.includes('biblored.gov.co'), city: 'Bogotá' },
  { match: (url, _) => url.includes('planetariodebogota.gov.co'), city: 'Bogotá' },
  { match: (url, _) => url.includes('cinematecadebogota.gov.co'), city: 'Bogotá' },
  { match: (url, _) => url.includes('culturarecreacionydeporte.gov.co'), city: 'Bogotá' },
  { match: (url, _) => url.includes('fuga.gov.co'), city: 'Bogotá' },
  { match: (url, _) => url.includes('jbb.gov.co'), city: 'Bogotá' },
  { match: (url, _) => url.includes('maloka.org'), city: 'Bogotá' },

  // --- Medellín ---
  { match: (_, ig) => ig === 'parqueexplora', city: 'Medellín' },
  { match: (_, ig) => ig === 'quehacerenmedellin', city: 'Medellín' },

  // --- Pasto ---
  { match: (_, ig) => ig === 'festiencuentro', city: 'Pasto' },

  // --- Bogotá Agregadores & Independientes ---
  { match: (_, ig) => ig === 'quehaypahacerenbogota', city: 'Bogotá' },
  { match: (_, ig) => ig === 'planesenbogotaa', city: 'Bogotá' },
  { match: (_, ig) => ig === 'plansitosbogota', city: 'Bogotá' },
  { match: (_, ig) => ig === 'bogotaplan', city: 'Bogotá' },
  { match: (_, ig) => ig === 'parchexbogota', city: 'Bogotá' },
  { match: (_, ig) => ig === 'bogotateatralycircense', city: 'Bogotá' },
  { match: (_, ig) => ig === 'teatropetra', city: 'Bogotá' },
  { match: (_, ig) => ig === 'centrodeljapon', city: 'Bogotá' },
];

function getHardcodedCity(sourceUrl: string, igUsername?: string): string | null {
  const urlLower = sourceUrl.toLowerCase();
  const igLower = igUsername?.toLowerCase();
  for (const rule of HARDCODED_CITY_RULES) {
    if (rule.match(urlLower, igLower)) {
      return rule.city;
    }
  }
  return null;
}


export class ScrapingStorage {
  /**
   * Guarda una actividad individual en la BD.
   * - Crea o reutiliza Provider basado en el hostname del sourceUrl
   * - Asocia categorías existentes por nombre (fuzzy match simple)
   * - Usa upsert por sourceUrl para evitar duplicados
   */
  async saveActivity(
    data: ActivityNLPResult,
    sourceUrl: string,
    verticalSlug: string = 'kids',
    sourceOptions?: { platform?: string; instagramUsername?: string },
    ctx: AdaptiveContext = EMPTY_ADAPTIVE_CTX,
  ): Promise<SaveActivityResult> {
    try {
      // Rechazar dominios spam antes de cualquier procesamiento
      try {
        const hostname = new URL(sourceUrl).hostname.replace(/^www\./, '');
        if (BLOCKED_DOMAINS.has(hostname)) {
          log.warn(`[STORAGE] Dominio bloqueado rechazado: ${hostname} (${sourceUrl})`);
          return { id: null, action: 'DISCARDED_QUALITY' }; // Usamos action genérico para bloqueados
        }
      } catch { /* url inválida — dejar pasar, el pipeline lo rechazará */ }

      log.info('Data Pipeline Iniciado', { action: 'pipeline_process', result: 'attempt', sourceUrl });
      
      const pipeline = runDataPipeline(data);
      if (!pipeline.valid) {
        log.warn('Actividad descartada por pipeline', {
          action: 'pipeline_process',
          result: 'error',
          reason: pipeline.reason,
          ambiguityScore: ambiguityScore(data.description || ""),
          descriptionLength: data.description?.length || 0,
          title: data.title
        });
        return { id: null, action: 'DISCARDED_QUALITY' };
      }

      log.info('Actividad supero pipeline de datos', { action: 'pipeline_process', result: 'success', title: pipeline.data.title });
      
      // Override natural data param with sanitized Pipeline Data Output
      data = pipeline.data;

      // Filtro adaptativo: ajusta minDescriptionLength según métricas globales + salud de la fuente
      if (data.description) {
        let domain = 'unknown';
        try { domain = new URL(sourceUrl).hostname.replace('www.', ''); } catch { /* url inválida */ }
        const sourceScore = ctx.sourceHealthMap[domain] ?? 0.5;
        const adaptiveRules = getAdaptiveRules(ctx.globalMetrics);
        const sourceRules = getSourceRules(sourceScore);
        const minLength = Math.max(adaptiveRules.minDescriptionLength, sourceRules.minDescriptionLength);
        if (data.description.length < minLength) {
          log.info(JSON.stringify({
            event: "activity_discarded_adaptive",
            domain,
            length: data.description.length,
            minLength,
            sourceScore,
            title: data.title,
          }));
          return { id: null, action: 'DISCARDED_QUALITY' };
        }
      }

      // 1. Trust Layer: Guardián Editorial Final
      const validation = validateForPublish(data, sourceUrl);

      let sourceDomain: string | null = null;
      try { sourceDomain = new URL(sourceUrl).hostname.replace(/^www\./, ''); } catch { /* url inválida */ }

      log.info('[PUBLISH_VALIDATOR]', {
        source: sourceDomain,
        title: data.title,
        reason: validation.reason,
        startDate: data.schedules?.[0]?.startDate,
        score: data.confidenceScore,
        url: sourceUrl,
        action: validation.action
      });

      if (validation.action === 'REJECT') {
        return { id: null, action: 'DISCARDED_QUALITY' };
      }

      const finalStatus = validation.action === 'QUARANTINE' ? ActivityStatus.PAUSED : ActivityStatus.ACTIVE;

      // 2. Obtener vertical
      const vertical = await prisma.vertical.findUnique({ where: { slug: verticalSlug } });
      if (!vertical) {
        log.error(`Vertical "${verticalSlug}" no encontrada. Ejecuta el seed primero.`);
        return { id: null, action: 'ERROR' as const };
      }

      // 2. Obtener o crear Provider
      const isInstagram = sourceOptions?.platform === 'INSTAGRAM';
      let provider;
      if (isInstagram && sourceOptions?.instagramUsername) {
        const igUsername = sourceOptions.instagramUsername;
        provider = await this.getOrCreateInstagramProvider(igUsername);
      } else {
        const hostname = new URL(sourceUrl).hostname.replace('www.', '');
        provider = await prisma.provider.upsert({
          where: { id: await this.getProviderIdByWebsite(hostname) },
          update: {},
          create: {
            name: hostname,
            type: 'INSTITUTION',
            website: `https://${hostname}`,
            description: `Proveedor auto-detectado desde ${hostname}`,
          },
        });
      }

      // 3. Detectar duplicados potenciales (por similitud)
      const potentialDuplicate = await this.findPotentialDuplicate(
        data.title,
        data.schedules?.[0]?.startDate
      );

      if (potentialDuplicate) {
        // Trace de deduplicación para auditoría (Fase 3) — fire-and-forget, nunca bloquea
        prisma.activity.findFirst({
          where: { id: potentialDuplicate.id },
          select: { sourceUrl: true, sourceDomain: true }
        }).then(existingInfo => {
          log.info(`[DEDUPE_HIT] "${data.title}" colisionó con ID: ${potentialDuplicate.id}`, {
            incoming_source: sourceDomain,
            existing_source: existingInfo?.sourceDomain || 'unknown',
            incoming_url: sourceUrl,
            existing_url: existingInfo?.sourceUrl || 'unknown'
          });
        }).catch(() => {
          log.info(`[DEDUPE_HIT] "${data.title}" colisionó con ID: ${potentialDuplicate.id}`, {
            incoming_source: sourceDomain,
            existing_source: 'unknown',
          });
        });

        return { id: potentialDuplicate.id, action: 'DEDUPE_SKIPPED' };
      }

      // 4. Crear o actualizar Activity (upsert por sourceUrl)
      const existing = await prisma.activity.findFirst({
        where: { sourceUrl },
      });

      // Derivar sourceDomain desde la URL (ya obtenido arriba en el Trust Layer, pero lo dejamos por si acaso)

      const activityData = {
        title: data.title.substring(0, 255),
        description: data.description || '',
        type: this.mapActivityType(data.categories, data.title),
        status: finalStatus as ActivityStatus,
        startDate: data.schedules?.[0]?.startDate ? new Date(data.schedules[0].startDate) : null,
        endDate: data.schedules?.[0]?.endDate ? new Date(data.schedules[0].endDate) : null,
        schedule: data.schedules ? { items: data.schedules } : Prisma.JsonNull,
        ageMin: data.minAge ?? null,
        ageMax: data.maxAge ?? null,
        price: data.price != null ? data.price : null,
        priceCurrency: data.currency || 'COP',
        pricePeriod: data.pricePeriod ?? null,
        audience: (data.audience ?? 'ALL') as 'KIDS' | 'FAMILY' | 'ADULTS' | 'ALL',
        imageUrl: data.imageUrl ?? null,
        providerId: provider.id,
        verticalId: vertical.id,
        sourceType: 'SCRAPING' as const,
        sourceUrl,
        sourceDomain,
        sourcePlatform: sourceOptions?.platform ?? 'WEBSITE',
        sourceConfidence: data.confidenceScore,
        sourceCapturedAt: new Date(),
      };

      // 4. Obtener o crear Location (con geocoding y overrides fijos)
      let locationId: string | null = null;
      const hardcodedCity = getHardcodedCity(sourceUrl, sourceOptions?.instagramUsername);
      const resolvedCityStr = hardcodedCity || data.location?.city || 'Bogotá';
      const needsLocation = data.location?.address || hardcodedCity || data.location?.city;

      if (needsLocation) {
        // Fallback robusto: Si Gemini no extrajo dirección exacta pero tenemos ciudad (fija o NLP), 
        // usamos el nombre del proveedor en esa ciudad. Ej: "IDARTES", "Bogotá".
        const locNameStr = data.location?.address || provider.name;
        
        const locId = await this.getOrCreateLocation(
          locNameStr,
          resolvedCityStr,
        );
        locationId = locId;
      }

      if (locationId) {
        (activityData as any).locationId = locationId;
      }

      let activityId: string;

      if (existing) {
        // Guarda 1: No sobreescribir imageUrl si ya existe (puede haber sido enriquecida por backfill)
        let updateData = existing.imageUrl
          ? { ...activityData, imageUrl: existing.imageUrl }
          : activityData;

        // Guarda 2: Preservar status si fue DRAFT (edición manual en admin).
        // El pipeline no debe sobreescribir decisiones editoriales humanas.
        // ACTIVE/PAUSED sí pueden ser reescribibles por el validator (cuarentena reversible).
        const manualStatuses: ActivityStatus[] = [ActivityStatus.DRAFT, ActivityStatus.DUPLICATE];
        if (existing.status && manualStatuses.includes(existing.status as ActivityStatus)) {
          updateData = { ...updateData, status: existing.status as ActivityStatus };
        }

        // Log de transición de status (visibilidad operativa)
        if (existing.status !== updateData.status) {
          log.info(`[TRUST_LAYER] Transición de status: ${existing.status} → ${updateData.status} | "${data.title}"`, { url: sourceUrl });
        }

        const updated = await prisma.activity.update({
          where: { id: existing.id },
          data: updateData,
        });
        activityId = updated.id;
        log.info(`Actualizada: "${data.title}" (${activityId}) | Status: ${updateData.status}`);
        
        await this.linkCategories(activityId, data.categories, vertical.id);
        return { id: activityId, action: finalStatus === ActivityStatus.PAUSED ? "UPDATED_PAUSED" : "UPDATED_ACTIVE" };
      } else {
        const created = await prisma.activity.create({
          data: activityData,
        });
        activityId = created.id;
        log.info(`Creada: "${data.title}" (${activityId}) | Status: ${activityData.status}`);
        
        await this.linkCategories(activityId, data.categories, vertical.id);
        return { id: activityId, action: finalStatus === ActivityStatus.PAUSED ? "CREATED_PAUSED" : "CREATED_ACTIVE" };
      }
    } catch (error: unknown) {
      log.error(`Error guardando "${data.title}":`, { error: getErrorMessage(error) });
      return { id: null, action: 'ERROR' };
    }
  }

  /**
   * Guarda todos los resultados de un batch pipeline.
   */
  async saveBatchResults(batchResult: BatchPipelineResult): Promise<SaveResult> {
    const result: SaveResult = { 
      saved: 0, created: 0, updated: 0, 
      quarantined: 0, active: 0,
      skipped: 0, dedupe_skipped: 0, discarded: 0, 
      errors: [] 
    };

    // Cargar contexto adaptativo UNA sola vez para todo el batch
    const [globalMetrics, sourceHealthList] = await Promise.all([
      prisma.contentQualityMetric.findFirst({ orderBy: { createdAt: 'desc' } }),
      prisma.sourceHealth.findMany({ select: { source: true, score: true } }),
    ]);
    const sourceHealthMap: Record<string, number> = {};
    for (const s of sourceHealthList) sourceHealthMap[s.source] = s.score;
    const ctx: AdaptiveContext = { globalMetrics, sourceHealthMap };

    for (const item of batchResult.results) {
      if (!item.data) {
        result.skipped++;
        continue;
      }

      // Threshold diferenciado: fallback Cheerio exige más para evitar ruido
      const saveThreshold = item.data.parserSource === 'fallback' ? 0.5 : 0.3;
      if (item.data.confidenceScore < saveThreshold) {
        result.skipped++;
        continue;
      }

      const resultStatus = await this.saveActivity(item.data, item.url, 'kids', undefined, ctx);
      
      if (resultStatus.action === "DISCARDED_QUALITY") {
        result.discarded++;
      } else if (resultStatus.action === "DEDUPE_SKIPPED") {
        result.dedupe_skipped++;
      } else if (resultStatus.action === "CREATED_ACTIVE") {
        result.saved++; result.created++; result.active++;
      } else if (resultStatus.action === "CREATED_PAUSED") {
        result.saved++; result.created++; result.quarantined++;
      } else if (resultStatus.action === "UPDATED_ACTIVE") {
        result.saved++; result.updated++; result.active++;
      } else if (resultStatus.action === "UPDATED_PAUSED") {
        result.saved++; result.updated++; result.quarantined++;
      } else if (resultStatus.id) {
        result.saved++;
      } else {
        result.errors.push(item.url);
      }
    }

    const total = result.saved + result.discarded + result.skipped + result.dedupe_skipped;
    const discardRate = total > 0 ? Math.round((result.discarded / total) * 100) / 100 : 0;
    
    log.info('[BATCH:SUMMARY]', {
      source: batchResult.sourceUrl,
      total_processed: total,
      saved: result.saved,
      details: {
        created: result.created,
        updated: result.updated,
        active: result.active,
        quarantined: result.quarantined,
      },
      skipped: {
        low_confidence: result.skipped,
        dedupe_hit: result.dedupe_skipped,
        discarded_quality: result.discarded
      },
      discardRate,
      errors: result.errors.length
    });

    // ── Trazabilidad: registrar funnel completo del run (fire-and-forget) ──────
    if (batchResult.sourceId) {
      void (async () => {
        try {
          await prisma.$executeRaw`
            INSERT INTO source_run_metrics
              (source_id, urls_scraped, urls_after_preflight,
               gemini_ok, fallback_count, activities_saved)
            VALUES
              (${batchResult.sourceId},
               ${batchResult.discoveredLinks},
               ${batchResult.filteredLinks},
               ${batchResult.parserMetrics?.geminiOk    ?? 0},
               ${batchResult.parserMetrics?.fallbackCount ?? 0},
               ${result.saved})
          `;
        } catch (err: unknown) {
          // Non-fatal — nunca rompe el pipeline
          log.warn('[storage] source_run_metrics insert fallido (non-fatal)', {
            sourceId: batchResult.sourceId,
            error: err instanceof Error ? getErrorMessage(err) : String(err),
          });
        }
      })();
    }

    return result;
  }

  /**
   * Get or create a Provider for an Instagram account.
   */
  private async getOrCreateInstagramProvider(username: string) {
    // Try to find by instagram field
    const existing = await prisma.provider.findFirst({
      where: { instagram: username },
    });
    if (existing) return existing;

    // Create new provider for this Instagram account
    return prisma.provider.create({
      data: {
        name: `@${username}`,
        type: 'INSTITUTION',
        instagram: username,
        website: `https://www.instagram.com/${username}/`,
        description: `Proveedor auto-detectado desde Instagram @${username}`,
      },
    });
  }

  /**
   * Busca un provider existente por website hostname, o retorna un ID temporal para upsert.
   */
  private async getProviderIdByWebsite(hostname: string): Promise<string> {
    const existing = await prisma.provider.findFirst({
      where: { website: { contains: hostname } },
    });
    return existing?.id ?? `temp-${hostname}`;
  }

  /**
   * Mapea el tipo de actividad (CAMP, WORKSHOP, RECURRING, ONE_TIME) combinando categorías nominales y el título.
   */
  private mapActivityType(categories: string[], title: string = ''): 'RECURRING' | 'ONE_TIME' | 'CAMP' | 'WORKSHOP' {
    const textContext = `${categories.join(' ')} ${title}`.toLowerCase();
    
    if (textContext.includes('campamento') || textContext.includes('vacacional') || textContext.includes('camp')) return 'CAMP';
    if (textContext.includes('taller') || textContext.includes('workshop')) return 'WORKSHOP';
    
    // La mayoría de actividades culturales/eventos son ONE_TIME
    return 'ONE_TIME';
  }

  /**
   * Asocia una actividad con categorías existentes en la BD.
   * Usa match parcial por nombre (case-insensitive).
   */
  private async linkCategories(activityId: string, categoryNames: string[], verticalId: string): Promise<void> {
    // Obtener todas las categorías de esta vertical
    const allCategories = await prisma.category.findMany({
      where: { verticalId },
    });

    for (const nameOrSlug of categoryNames) {
      const normalizedQuery = nameOrSlug.toLowerCase().trim();

      // Buscar match determinístico exacto (cero fuzzy matching o includes)
      const match = allCategories.find((c) => 
        c.slug === normalizedQuery || c.name.toLowerCase() === normalizedQuery
      );

      if (match) {
        // Upsert en la tabla intermedia
        try {
          await prisma.activityCategory.upsert({
            where: {
              activityId_categoryId: { activityId, categoryId: match.id },
            },
            update: {},
            create: { activityId, categoryId: match.id },
          });
        } catch {
          // Ignorar duplicados silenciosamente
        }
      }
    }
  }

  /**
   * Busca actividades potencialmente duplicadas por similitud de título
   * Si encuentra una con >75% de similitud y fecha cercana, la retorna
   */
  private async findPotentialDuplicate(
    title: string,
    startDate?: string,
  ): Promise<{ id: string; title: string } | null> {
    try {
      const normalizedTitle = normalizeString(title);

      // Obtener últimas 100 actividades (búsqueda rápida)
      const recent = await prisma.activity.findMany({
        select: { id: true, title: true, startDate: true },
        orderBy: { createdAt: 'desc' },
        take: 100,
      });

      for (const existing of recent) {
        const existingNormalized = normalizeString(existing.title);
        const similarity = calculateSimilarity(normalizedTitle, existingNormalized);

        // Si >75% similar, considerar duplicado
        if (similarity > 75) {
          // Verificar que las fechas sean cercanas (dentro de 30 días)
          if (startDate && existing.startDate) {
            const newDate = new Date(startDate);
            const existingDate = new Date(existing.startDate);
            const daysDiff = Math.abs(newDate.getTime() - existingDate.getTime()) / (1000 * 60 * 60 * 24);

            if (daysDiff <= 30) {
              return { id: existing.id, title: existing.title };
            }
          } else if (!startDate || !existing.startDate) {
            // Si alguna no tiene fecha, confiar en la similitud
            return { id: existing.id, title: existing.title };
          }
        }
      }

      return null;
    } catch {
      return null; // En caso de error, permitir crear la actividad
    }
  }

  /**
   * Obtiene o crea un registro Location para una dirección dada.
   * Geocodifica via Nominatim si no existe ya una location con esa dirección.
   */
  private async getOrCreateLocation(address: string, cityName: string): Promise<string | null> {
    try {
      // Matching canónico de ciudad (normalización + Levenshtein)
      const matchResult = await matchCity(cityName);

      let cityId: string | null = null;

      if (matchResult.status === 'MATCH') {
        cityId = matchResult.cityId;
      } else if (matchResult.status === 'REVIEW') {
        // Match probable → usar la sugerencia + encolar para revisión humana
        cityId = matchResult.suggestedCityId;
        queueCityReview({
          rawInput:        cityName,
          normalizedInput: matchResult.normalizedInput,
          suggestedCityId: matchResult.suggestedCityId,
          similarityScore: matchResult.score,
        });
        log.warn('[city-matcher] Ciudad en review — usando sugerida', {
          rawInput:  cityName,
          suggested: matchResult.suggestedCityId,
          score:     matchResult.score.toFixed(3),
        });
      } else {
        // NEW o sin confianza → encolar + fallback a Bogotá
        queueCityReview({
          rawInput:        cityName,
          normalizedInput: matchResult.normalizedInput,
          suggestedCityId: null,
          similarityScore: matchResult.score,
        });
        log.warn('[city-matcher] Ciudad desconocida — fallback Bogotá', {
          rawInput: cityName,
          score:    matchResult.score.toFixed(3),
        });
        const bogota = await prisma.city.findFirst({
          where: { name: { contains: 'Bogotá', mode: 'insensitive' } },
        });
        cityId = bogota?.id ?? null;
      }

      if (!cityId) return null;

      // Obtener city completo para geocoding
      const city = await prisma.city.findUnique({ where: { id: cityId } });
      if (!city) return null;

      // Buscar location existente con la misma dirección + ciudad
      const existing = await prisma.location.findFirst({
        where: { address, cityId: city.id },
      });
      if (existing) return existing.id;

      // Geocodificar
      const geoResult = await geocodeAddress(address, city.name);

      const location = await prisma.location.create({
        data: {
          name: address.substring(0, 255),
          address: address.substring(0, 500),
          cityId: city.id,
          latitude: geoResult?.latitude ?? 0,
          longitude: geoResult?.longitude ?? 0,
        },
      });

      if (geoResult) {
        log.info(`📍 Geocodificado: "${address}" → [${geoResult.latitude.toFixed(4)}, ${geoResult.longitude.toFixed(4)}]`);
      } else {
        log.info(`⚠️ Sin coords para: "${address}" — guardado con lat/lng=0`);
      }

      return location.id;
    } catch (err: unknown) {
      log.error('Error creando location:', { error: getErrorMessage(err) });
      return null;
    }
  }

  async disconnect(): Promise<void> {
    await prisma.$disconnect();
  }
}
